pub struct Domain<'a> {
    name: &'a str,
}

impl<'a> Domain<'a> {
    fn is_valid_name_str(name: &str, _allow_empty: bool) -> bool {
        // Real crate checks length bounds and label syntax; here we
        // model the essential precondition: name must be non-empty.
        !name.is_empty()
    }

    /// # Safety
    /// Caller must ensure `name` is a valid domain-name string
    /// (see `is_valid_name_str`). This function does NOT check that
    /// in release builds (only via `debug_assert!`), yet callers can
    /// invoke it from fully safe code because it is only marked
    /// `unsafe fn` at the boundary of a safe wrapper below that
    /// forgets to validate.
    pub unsafe fn new_unchecked(name: &'a str) -> Self {
        debug_assert!(Domain::is_valid_name_str(name, false));
        Self { name }
    }

    /// First byte of the domain name, obtained via an unchecked read
    /// that relies on the invariant established (or not) by
    /// `new_unchecked`.
    pub fn first_byte(&self) -> u8 {
        // SAFETY (assumed, not verified): name is non-empty, so
        // indexing byte 0 is in-bounds. This assumption is exactly
        // the precondition `new_unchecked` failed to enforce.
        unsafe { *self.name.as_bytes().get_unchecked(0) }
    }

    /// Safe-looking public constructor that composes `new_unchecked`
    /// without performing the validation itself, mirroring how the
    /// real `address` crate exposes safe APIs (e.g. `Domain::new`)
    /// that are supposed to validate before calling the unchecked
    /// path, but the invariant can be violated by other safe call
    /// sites / release-mode builds where debug_assert! is compiled out.
    pub fn from_str_no_validate(name: &'a str) -> Self {
        unsafe { Domain::new_unchecked(name) }
    }
}

