use poc_lib::Domain;

fn main() {
    // Fully safe Rust: no `unsafe` keyword here at all.
    let empty = String::new();
    let domain = Domain::from_str_no_validate(&empty);

    // In a release build debug_assert! is stripped, so the invalid
    // (empty) name sails through new_unchecked, and this call performs
    // an out-of-bounds read via get_unchecked(0) on an empty slice.
    let b = domain.first_byte();
    println!("{}", b);
}

