unsafe fn drop_range(&mut self, range: Range<usize>) {
    if range.is_empty() {
        return;
    }

    debug_assert!(self.start < N, "start out-of-bounds");
    debug_assert!(self.size <= N, "size out-of-bounds");
    debug_assert!(range.start < self.size, "start of range out-of-bounds");
    debug_assert!(range.end <= self.size, "end of range out-of-bounds");
    debug_assert!(range.start < range.end, "start of range is past its end");
    debug_assert!(range.start == 0 || range.end == self.size,
                  "range does not include boundary of the buffer");

    // Drops all the items in the slice when dropped. This is needed to ensure that all
    // elements are dropped in case a panic occurs during the drop of a single element.
    struct Dropper<'a, T>(&'a mut [MaybeUninit<T>]);

    impl<'a, T> Drop for Dropper<'a, T> {
        #[inline]
        fn drop(&mut self) {
            // SAFETY: the caller of `drop_range` is responsible to check that this slice was
            // initialized.
            unsafe { ptr::drop_in_place(slice_assume_init_mut(self.0)); }
        }
    }

    let drop_from = add_mod(self.start, range.start, N);
    let drop_to = add_mod(self.start, range.end, N);

    let (right, left) = if drop_from < drop_to {
        (&mut self.items[drop_from..drop_to], &mut [][..])
    } else {
        let (left, right) = self.items.split_at_mut(drop_from);
        let left = &mut left[..drop_to];
        (right, left)
    };

    let _left = Dropper(left);
    let _right = Dropper(right);
}

poc_lib_rs:
use std::mem::MaybeUninit;
use std::ops::Range;
use std::ptr;

fn add_mod(a: usize, b: usize, n: usize) -> usize {
    (a + b) % n
}

unsafe fn slice_assume_init_mut<T>(slice: &mut [MaybeUninit<T>]) -> &mut [T] {
    unsafe { &mut *(slice as *mut [MaybeUninit<T>] as *mut [T]) }
}

pub struct CircularBuffer<const N: usize, T> {
    items: [MaybeUninit<T>; N],
    start: usize,
    size: usize,
}

impl<const N: usize, T> CircularBuffer<N, T> {
    pub fn new() -> Self {
        Self {
            // Standard idiom: array of `MaybeUninit<T>` needs no initialization.
            items: unsafe { MaybeUninit::uninit().assume_init() },
            start: 0,
            size: 0,
        }
    }

    pub fn len(&self) -> usize {
        self.size
    }

    /// Safe, correctly-initializing push used for the sane parts of the API.
    pub fn push_back(&mut self, value: T) {
        assert!(self.size < N, "buffer full");
        let idx = add_mod(self.start, self.size, N);
        self.items[idx].write(value);
        self.size += 1;
    }

    /// Bulk-insert helper. BUG: it advances the logical `size` using the
    /// iterator's advertised `size_hint()` lower bound *before* confirming
    /// that many items actually exist, trusting a safe trait method that has
    /// no correctness contract.
    pub fn extend_from_iter<I: Iterator<Item = T>>(&mut self, mut iter: I) {
        let (hint, _) = iter.size_hint();
        let n = hint.min(N - self.size);
        let base = self.size;
        self.size += n; // logical length now claims `n` new initialized slots
        for i in 0..n {
            match iter.next() {
                Some(value) => {
                    let idx = add_mod(self.start, base + i, N);
                    self.items[idx].write(value);
                }
                None => break, // remaining slots never written, yet already counted in `size`
            }
        }
    }

    // Reconstruction of the target function, semantics preserved.
    unsafe fn drop_range(&mut self, range: Range<usize>) {
        if range.is_empty() {
            return;
        }

        debug_assert!(self.start < N, "start out-of-bounds");
        debug_assert!(self.size <= N, "size out-of-bounds");
        debug_assert!(range.start < self.size, "start of range out-of-bounds");
        debug_assert!(range.end <= self.size, "end of range out-of-bounds");
        debug_assert!(range.start < range.end, "start of range is past its end");
        debug_assert!(
            range.start == 0 || range.end == self.size,
            "range does not include boundary of the buffer"
        );

        struct Dropper<'a, T>(&'a mut [MaybeUninit<T>]);

        impl<'a, T> Drop for Dropper<'a, T> {
            #[inline]
            fn drop(&mut self) {
                // SAFETY (per original crate): caller of `drop_range` must ensure
                // this slice was initialized. `extend_from_iter` breaks that
                // precondition without ever using `unsafe` itself.
                unsafe {
                    ptr::drop_in_place(slice_assume_init_mut(self.0));
                }
            }
        }

        let drop_from = add_mod(self.start, range.start, N);
        let drop_to = add_mod(self.start, range.end, N);

        let (right, left) = if drop_from < drop_to {
            (&mut self.items[drop_from..drop_to], &mut [][..])
        } else {
            let (left, right) = self.items.split_at_mut(drop_from);
            let left = &mut left[..drop_to];
            (right, left)
        };

        let _left = Dropper(left);
        let _right = Dropper(right);
    }
}

impl<const N: usize, T> Drop for CircularBuffer<N, T> {
    fn drop(&mut self) {
        if self.size > 0 {
            unsafe {
                self.drop_range(0..self.size);
            }
        }
    }
}

