use poc_lib::CircularBuffer;

/// A perfectly safe iterator that lies about `size_hint`: it advertises 5
/// upcoming items but only ever yields 1. Nothing about this is `unsafe` --
/// `Iterator::size_hint` carries no correctness contract.
struct LyingIter {
    yielded: usize,
}

impl Iterator for LyingIter {
    type Item = String;

    fn next(&mut self) -> Option<String> {
        if self.yielded == 0 {
            self.yielded += 1;
            Some(String::from("hi"))
        } else {
            None
        }
    }

    fn size_hint(&self) -> (usize, Option<usize>) {
        (5, Some(5))
    }
}

fn main() {
    let mut buf: CircularBuffer<8, String> = CircularBuffer::new();

    // Fully safe call site: no `unsafe` anywhere here.
    buf.extend_from_iter(LyingIter { yielded: 0 });

    println!("logical len = {}", buf.len()); // prints 5, but only 1 String was ever written

    // `buf` goes out of scope here; `Drop` calls `drop_range(0..5)`, which
    // calls `drop_in_place` over 5 `String`s while 4 of them are still raw
    // uninitialized bytes -> reads/frees garbage pointers -> UB.
}

