use std::collections::VecDeque;

pub type Datum = u32;

#[derive(Debug)]
pub enum Sign {
    Positive,
}
use Sign::Positive;

pub struct BigUint {
    pub sign: Sign,
    pub data: VecDeque<Datum>,
    pub start_offset: usize,
    pub end_offset: usize,
}

impl BigUint {
    // Faithful reconstruction of the target function: no validation that
    // start_offset <= end_offset <= data.len().
    pub unsafe fn from_raw_parts(
        data: VecDeque<Datum>,
        start_offset: usize,
        end_offset: usize,
    ) -> Self {
        Self {
            sign: Positive,
            data,
            start_offset,
            end_offset,
        }
    }

    // Mirrors how the crate's internal unsafe code trusts the offsets to
    // compute a valid logical length and read within bounds.
    pub fn read_digit(&self, i: usize) -> Datum {
        let len = self.end_offset - self.start_offset;
        assert!(i < len, "logical index in range"); // relies on end_offset being trustworthy
        unsafe { *self.data.get(self.start_offset + i).unwrap_unchecked() }
    }
}

// Safe public wrapper that a safe caller can use without writing `unsafe`
// themselves, composing the module's API into an invalid state.
pub fn make_biguint_with_bad_offsets(data: VecDeque<Datum>, start: usize, end: usize) -> BigUint {
    unsafe { BigUint::from_raw_parts(data, start, end) }
}

poc_main_rs:
use poc_lib::make_biguint_with_bad_offsets;
use std::collections::VecDeque;

fn main() {
    let data: VecDeque<u32> = VecDeque::from(vec![1, 2, 3]);

    // Safe Rust: only 3 elements exist, but end_offset claims 100.
    let n = make_biguint_with_bad_offsets(data, 0, 100);

    // Reading past the real length dereferences an out-of-bounds / None
    // option via unwrap_unchecked, i.e. undefined behavior, all from safe code.
    let v = n.read_digit(50);
    println!("{}", v);
}

