use std::ptr;

/// Minimal stand-in for a Method's per-instance state (like `F` in gdnative-core).
pub struct MethodData {
    pub value: u64,
}

/// Minimal stand-in for the C-FFI-facing wrapper that gdnative-core registers as
/// the callback invoked by Godot. It mirrors the real `method_wrapper`: it only
/// checks `user_data` for null, then blindly casts and dereferences it, trusting
/// that whoever registered the pointer keeps it valid for the callback's lifetime.
/// This function itself is safe to *call* (no `unsafe` keyword needed at the call
/// site) even though its body performs a raw pointer read.
pub fn method_wrapper(user_data: *mut MethodData) -> u64 {
    if user_data.is_null() {
        // Mirrors the real wrapper's null check -- but only null is checked,
        // not liveness/validity of the pointee.
        return 0;
    }

    // SAFETY (in the original crate): assumes `user_data` points to a live `F`
    // for as long as Godot may invoke this callback. Nothing enforces that here.
    let data = unsafe { &*user_data };
    data.value
}

/// Safe-looking registration API: takes ownership of a `Box<MethodData>` and
/// hands back the raw pointer that would be stored as `user_data`, exactly as
/// gdnative-core's binding machinery stores a boxed `F` and later passes the
/// raw pointer to `method_wrapper`. No `unsafe` needed to call this.
pub fn register_method(data: MethodData) -> *mut MethodData {
    Box::into_raw(Box::new(data))
}

/// Safe-looking "cleanup" API that a safe caller might legitimately call when
/// unregistering/reloading a class -- mirrors object destruction in Godot
/// freeing the instance's user_data. No `unsafe` needed to call this.
pub fn unregister_method(ptr: *mut MethodData) {
    // Frees the box; ptr becomes dangling but is NOT nulled -- exactly like a
    // stale user_data pointer left registered with Godot after the instance
    // backing it is destroyed.
    unsafe {
        drop(Box::from_raw(ptr));
    }
    let _ = ptr::eq(ptr, ptr); // no-op, keeps ptr usage realistic
}

poc_main_rs:
use poc::{method_wrapper, register_method, unregister_method, MethodData};

fn main() {
    // Register a method's data, just like gdnative-core boxing `F` and storing
    // the raw pointer as `user_data` for Godot to pass back on every call.
    let ptr = register_method(MethodData { value: 42 });

    // Simulate the instance being destroyed (e.g. Godot frees the object, or
    // the class is reloaded) while the raw pointer remains registered as
    // user_data -- this mirrors a dangling-but-non-null `user_data` reaching
    // `method_wrapper`.
    unregister_method(ptr);

    // Purely safe Rust: no `unsafe` keyword here. The wrapper's null check
    // passes (ptr is non-null), so it dereferences freed memory -- UB.
    let value = method_wrapper(ptr);
    println!("got value: {}", value);
}

