// Minimal reconstruction of an svd2rust-style register field accessor
// (atsamd-usb-host style `bits()`), plus the typed read-back path that
// makes an out-of-range write observable as UB.

#[repr(u8)]
#[derive(Debug)]
pub enum Variant {
    A = 0,
    B = 1,
    C = 2,
}

#[derive(Default)]
pub struct W {
    bits: u8,
}

pub struct FieldWriter<'a> {
    w: &'a mut W,
}

impl<'a> FieldWriter<'a> {
    // Target function, semantics preserved verbatim from atsamd-usb-host.
    // Field is 3 bits wide (POS=5, MASK=0x7) but only 0..=2 are valid
    // `Variant` encodings -- no check is performed here.
    pub unsafe fn bits(self, v: u8) -> &'a mut W {
        const POS: u8 = 5;
        const MASK: u8 = 0x7;
        self.w.bits &= !((MASK as u8) << POS);
        self.w.bits |= ((v & MASK) as u8) << POS;
        self.w
    }
}

pub struct R {
    bits: u8,
}

impl R {
    // Mirrors svd2rust's typed field decode: unchecked transmute from the
    // raw stored bits to the field's enum type.
    pub fn variant(&self) -> Variant {
        const POS: u8 = 5;
        const MASK: u8 = 0x7;
        let raw = (self.bits >> POS) & MASK;
        unsafe { core::mem::transmute::<u8, Variant>(raw) }
    }
}

#[derive(Default)]
pub struct Register {
    w: W,
}

impl Register {
    pub fn new() -> Self {
        Self::default()
    }

    fn writer(&mut self) -> FieldWriter<'_> {
        FieldWriter { w: &mut self.w }
    }

    pub fn read(&self) -> R {
        R { bits: self.w.bits }
    }

    // Safe public wrapper around the unsafe accessor -- this is the
    // "modular unsafe function": the crate hides the unsafe call behind
    // a safe API, so no caller-side `unsafe` is needed or possible.
    pub fn set_field(&mut self, v: u8) {
        unsafe {
            self.writer().bits(v);
        }
    }
}

poc_main_rs:
#![forbid(unsafe_code)]

fn main() {
    let mut reg = poc_lib::Register::new();

    // Entirely safe call: no bounds/validity check exists between the
    // 3-bit-wide raw field and the 3-valued `Variant` enum.
    reg.set_field(7); // valid range for the field is 0..=2

    let r = reg.read();
    let v = r.variant(); // decodes raw bits 7 as `Variant` -> invalid discriminant, UB
    println!("{:?}", v);
}

