use std::os::raw::c_char;
use std::slice;
use std::str;

#[repr(C)]
pub struct TSHighlighter {
    pub languages: Vec<String>,
}

impl TSHighlighter {
    pub fn new() -> Self {
        TSHighlighter { languages: Vec::new() }
    }
}

#[derive(Debug)]
pub enum ErrorCode {
    Ok,
    InvalidUtf8,
}

unsafe fn unwrap_mut_ptr<'a, T>(ptr: *mut T) -> &'a mut T {
    &mut *ptr
}

// Faithful reconstruction of jellybean-tree-sitter-highlight's
// ts_highlighter_add_language: it reconstructs the query buffer from a
// raw pointer plus a caller-controlled length, with no check that the
// length matches the pointer's real allocation.
pub unsafe extern "C" fn ts_highlighter_add_language(
    this: *mut TSHighlighter,
    highlight_query: *const c_char,
    highlight_query_len: u32,
) -> ErrorCode {
    let f = move || {
        let this = unwrap_mut_ptr(this);

        let highlight_query =
            slice::from_raw_parts(highlight_query as *const u8, highlight_query_len as usize);
        let highlight_query = str::from_utf8(highlight_query).or(Err(ErrorCode::InvalidUtf8))?;

        this.languages.push(highlight_query.to_string());
        Ok(())
    };

    match f() {
        Ok(()) => ErrorCode::Ok,
        Err(e) => e,
    }
}

// Safe-looking wrapper mirroring how the crate's higher-level Rust API
// forwards a query string and a separately supplied length to the C ABI
// entry point. It never verifies that `len` matches `query`'s actual byte
// length, so a fully safe caller can request more bytes than exist.
pub fn add_highlight_query(this: &mut TSHighlighter, query: &str, len: u32) -> ErrorCode {
    unsafe {
        ts_highlighter_add_language(
            this as *mut TSHighlighter,
            query.as_ptr() as *const c_char,
            len,
        )
    }
}

poc_main_rs:
use poc_lib::{add_highlight_query, TSHighlighter};

fn main() {
    let mut highlighter = TSHighlighter::new();

    // A tiny 3-byte string literal.
    let query = "abc";

    // Purely safe value: nothing stops a caller from claiming the buffer
    // is much larger than it really is.
    let claimed_len: u32 = 1024;

    let code = add_highlight_query(&mut highlighter, query, claimed_len);
    println!("{:?}", code);
    println!("{:?}", highlighter.languages);
}

