// Minimal faithful reconstruction of bitvec's BitSliceIndex-style unchecked
// indexing pattern: a trait with an `unsafe fn get_unchecked` whose contract
// requires the caller to pre-validate the index/range, plus a *safe* public
// wrapper that fails to perform that validation before calling it.

pub trait SliceIndex<'a> {
    type Immut;

    /// # Safety
    /// The caller must guarantee `self` denotes a range within bounds of the
    /// slice `bits` was derived from. This function performs NO bounds check.
    unsafe fn get_unchecked(self, bits: Self::Immut) -> Self::Immut;
}

pub struct RangeIdx {
    pub start: usize,
    pub end: usize,
}

impl<'a> SliceIndex<'a> for RangeIdx {
    type Immut = &'a [u8];

    unsafe fn get_unchecked(self, bits: Self::Immut) -> Self::Immut {
        // Directly builds a new slice from raw parts using attacker-controlled
        // start/end with no validation -- mirrors the target function's body
        // (`bits` is handed straight to unsafe machinery untouched).
        let ptr = bits.as_ptr().add(self.start);
        core::slice::from_raw_parts(ptr, self.end - self.start)
    }
}

pub struct Slice<'a> {
    data: &'a [u8],
}

impl<'a> Slice<'a> {
    pub fn new(data: &'a [u8]) -> Self {
        Slice { data }
