    /// Public, entirely safe API -- but it fails to validate that `index`
    /// actually falls within `self.data` before handing it to the unsafe
    /// unchecked accessor. This is the missing precondition check.
    pub fn get(&self, index: RangeIdx) -> &'a [u8] {
        // MISSING: no check that index.end <= self.data.len() or
        // index.start <= index.end.
        unsafe { SliceIndex::get_unchecked(index, self.data) }
    }
}

