use std::ptr;

// Minimal reconstruction of the svd2rust-generated GPR register writer proxy
// (imxrt1062-iomuxc-gpr style): W holds the raw 32-bit register image, and
// the field-setter `bits()` masks a raw value into a 7-bit field with no
// validity check before it is committed to the memory-mapped register.
pub struct W {
    pub bits: u32,
}

pub struct FieldWriter<'a> {
    pub w: &'a mut W,
}

impl<'a> FieldWriter<'a> {
    // mirrors the target function's body semantics exactly (mask 0x7f << 1),
    // reachable from safe code with no `unsafe` at the call site
    pub fn bits(self, value: u8) -> &'a mut W {
        self.w.bits = (self.w.bits & !(0x7f << 1)) | (((value as u32) & 0x7f) << 1);
        self.w
    }
}

pub struct RegisterBlock {
    field: *mut u32,
}

impl RegisterBlock {
    pub fn new(addr: usize) -> Self {
        RegisterBlock { field: addr as *mut u32 }
    }

    // safe public entry point: builds the writer proxy, applies the
    // unchecked field write, then commits the resulting bit image to
    // the device register via a raw volatile store
    pub fn modify<F>(&mut self, f: F)
    where
        F: FnOnce(FieldWriter) -> &mut W,
    {
        let mut w = W { bits: 0 };
        let w = f(FieldWriter { w: &mut w });
        unsafe { ptr::write_volatile(self.field, w.bits) }
    }
}

