    let mut reg = RegisterBlock::new(0x4000_0000);

    // Fully safe call site: no `unsafe` keyword needed here at all.
    // 0xFF masked into a 7-bit field still yields a value with no
    // check against the field's valid encoding, and the resulting
    // bit image is pushed straight to the unmapped device register.
    reg.modify(|w| w.bits(0xFF));
}

