    Error = 1,
}

impl From<ArgVerbosity> for i32 {
    fn from(v: ArgVerbosity) -> Self {
        v as i32
    }
}

fn from_config_file(path: &str) -> Result<String, Box<dyn std::error::Error>> {
    Ok(path.to_string())
}

unsafe fn _over_tls_client_run(
    _config: String,
    _callback: Option<unsafe extern "C" fn(c_int, *mut c_void)>,
    _ctx: *mut c_void,
) -> Result<(), Box<dyn std::error::Error>> {
    Ok(())
}

/// Reconstruction of overtls's `over_tls_client_run`: it trusts that
/// `config_path` is a valid, NUL-terminated C string and never validates
/// that invariant beyond a null-pointer check.
pub unsafe extern "C" fn over_tls_client_run(
    config_path: *const c_char,
    _verbosity: ArgVerbosity,
    callback: Option<unsafe extern "C" fn(c_int, *mut c_void)>,
    ctx: *mut c_void,
) -> c_int {
    let result = || {
        if config_path.is_null() {
            return Err("config_path is null".into());
        }
        // No validation that the pointer is live / NUL-terminated: UB if not.
        let config_path = std::ffi::CStr::from_ptr(config_path).to_str()?;
        let config = from_config_file(config_path)?;
        _over_tls_client_run(config, callback, ctx)
    };
    match result() {
        Ok(_) => 0,
        Err(_) => -1,
    }
}

