use std::mem::MaybeUninit;

pub struct ArrBuilder<T, const N: usize> {
    arr: [MaybeUninit<T>; N],
    len: usize,
}

impl<T, const N: usize> ArrBuilder<T, N> {
    // Target function (kept verbatim in spirit): builds the container from a
    // fully-uninitialized backing array and resets the logical length to 0.
    pub const unsafe fn new(arr: [MaybeUninit<T>; N]) -> Self {
        Self { arr, len: 0 }
    }

    // Safe entry point: an array of `MaybeUninit<T>` has no validity
    // requirement, so producing one via `assume_init` is sound on its own.
    pub fn empty() -> Self {
        unsafe { Self::new(MaybeUninit::uninit().assume_init()) }
    }

    // Intended to be used only after `len` elements were actually written
    // via a (not-implemented-here) `push`, but nothing enforces that.
    pub fn set_len(&mut self, len: usize) {
        self.len = len;
    }

    // Trusts `len == N` as proof that every slot is initialized.
    pub fn into_array(self) -> [T; N] {
        assert_eq!(self.len, N, "not all elements initialized");
        unsafe { std::mem::transmute_copy(&self.arr) }
    }
}

