use std::ffi::c_void;
use std::os::raw::c_int;

pub type Socket = i32;

/// Minimal stand-in for c_ares_sys::ares_socket_t
pub type ares_socket_t = i32;

/// Registry entry mimicking what a safe wrapper stores to later invoke
/// the C-style callback with a `data` pointer it handed to the FFI layer.
pub struct SocketStateHandler {
    pub data: *mut c_void,
    pub callback: unsafe extern "C" fn(*mut c_void, ares_socket_t, c_int, c_int),
}

unsafe impl Send for SocketStateHandler {}

impl SocketStateHandler {
    /// Safe constructor: takes a plain reference to already-boxed closure
    /// memory and stores the raw pointer. Nothing here ties the pointer's
    /// lifetime to the handler's lifetime -- the caller can free the
    /// closure and this struct happily keeps the dangling pointer.
    pub fn new<F>(handler_ptr: *mut F) -> Self
    where
        F: FnMut(Socket, bool, bool) + Send + 'static,
    {
        SocketStateHandler {
            data: handler_ptr as *mut c_void,
            callback: socket_state_callback::<F>,
        }
    }

    /// Simulates the C library invoking the registered callback later,
    /// e.g. when a socket becomes readable/writable.
    pub fn fire(&self, fd: ares_socket_t, readable: bool, writable: bool) {
        unsafe {
            (self.callback)(self.data, fd, readable as c_int, writable as c_int);
        }
    }
}

/// Reconstruction of c-ares's socket_state_callback: kept verbatim in
/// semantics (catches panics, casts data back to *mut F, calls through it).
pub unsafe extern "C" fn socket_state_callback<F>(
    data: *mut c_void,
    socket_fd: ares_socket_t,
    readable: c_int,
    writable: c_int,
) where
    F: FnMut(Socket, bool, bool) + Send + 'static,
{
    let handler = data as *mut F;
    (*handler)(socket_fd, readable != 0, writable != 0);
}

/// Safe-looking helper a wrapper crate would expose: leaks a boxed
/// closure and returns the raw pointer needed to build a handler.
pub fn leak_closure<F>(f: F) -> *mut F
where
    F: FnMut(Socket, bool, bool) + Send + 'static,
{
    Box::into_raw(Box::new(f))
}

/// Safe-looking helper that frees a previously leaked closure pointer,
/// as a real wrapper's `Drop` impl would do when the handler is dropped.
pub fn free_closure<F>(ptr: *mut F) {
    unsafe {
        drop(Box::from_raw(ptr));
    }
}

