use poc_lib::{free_closure, leak_closure, SocketStateHandler};

fn main() {
    let ptr = leak_closure(|fd: i32, readable: bool, writable: bool| {
        println!("socket {} readable={} writable={}", fd, readable, writable);
    });

    let handler = SocketStateHandler::new(ptr);

    // Safe code frees the boxed closure through the safe wrapper API,
    // simulating the handler struct being dropped/replaced while the
    // FFI layer still references the same `data` pointer.
    free_closure(ptr);

    // The C library now "calls back" into the dangling pointer -- all
    // from safe Rust in main, no `unsafe` block here at all.
    handler.fire(7, true, false);
}

