use std::ptr::NonNull;

pub struct Node {
    pub marked: bool,
    pub value: i32,
}

#[derive(Clone, Copy)]
pub struct GcErasedPointer(pub NonNull<Node>);

/// Safe wrapper mirroring boa_gc's allocation entry point.
/// Registers a new heap node and returns a handle that can be pushed
/// into the `strong` vector by the caller -- entirely with safe code.
pub fn allocate(strong: &mut Vec<GcErasedPointer>, value: i32) -> GcErasedPointer {
    let boxed = Box::new(Node { marked: true, value });
    let ptr = NonNull::new(Box::into_raw(boxed)).unwrap();
    let handle = GcErasedPointer(ptr);
    strong.push(handle);
    handle
}

/// Safe API: caller can duplicate a handle into the vector again.
/// Nothing here re-validates that a pointer is unique in `strong`,
/// mirroring boa_gc's assumption that `strong` only ever holds each
/// live allocation once, an invariant `sweep` silently relies on.
pub fn duplicate_into(strong: &mut Vec<GcErasedPointer>, handle: GcErasedPointer) {
    strong.push(handle);
}

pub fn unmark_all(strong: &mut Vec<GcErasedPointer>) {
    for node in strong.iter() {
        // SAFETY (module-internal, not caller-visible): nodes in `strong`
        // are assumed to have been allocated via `allocate` and to be
        // unique, matching boa_gc's `heap_start` invariant.
        unsafe {
            (*node.0.as_ptr()).marked = false;
        }
    }
}

/// Reconstruction of boa_gc's `Gc::sweep`: retains marked nodes, drops
/// (frees) unmarked ones. Declared `unsafe fn` exactly like the real
/// target -- callers invoke it without writing `unsafe` because the
/// crate exposes a safe wrapper (`collect_garbage` below), just as
/// boa_gc's public GC API is entirely safe.
pub unsafe fn sweep(strong: &mut Vec<GcErasedPointer>) {
    strong.retain(|node| {
        // SAFETY: The caller must ensure the validity of every node.
        let node_ref = unsafe { node.0.as_ref() };
        if node_ref.marked {
            true
        } else {
            // SAFETY: The algorithm ensures only unmarked/unreachable
            // pointers are dropped, and that each pointer appears once.
            unsafe {
                drop(Box::from_raw(node.0.as_ptr()));
            }
            false
        }
    });
}

/// Safe public entry point (like boa_gc's `boa_gc::force_collect`).
/// No `unsafe` needed at the call site.
pub fn collect_garbage(strong: &mut Vec<GcErasedPointer>) {
    unmark_all(strong);
    unsafe {
        sweep(strong);
    }
}

poc_main_rs:
use poc_lib::{allocate, collect_garbage, duplicate_into};

fn main() {
    let mut strong = Vec::new();

    let handle = allocate(&mut strong, 42);
    // Safe misuse: push the SAME pointer into `strong` a second time.
    // This breaks boa_gc's implicit invariant that `strong` holds each
    // live allocation exactly once -- no unsafe block needed to do this.
    duplicate_into(&mut strong, handle);

    // First collection: both entries are unmarked (nothing marks them
    // as roots), so sweep's retain closure runs on both duplicate
    // entries. The first pass frees the node via Box::from_raw; the
    // second pass, still "unmarked" because the freed memory is gone,
    // dereferences the dangling pointer and frees it again.
    collect_garbage(&mut strong);
}

