poc_lib_rs:
// Self-contained model of the imxrt1062-dcp `bits()` field setter and the
// register apply step that performs the actual MMIO write.
// The setter itself does no range/encoding validation on `value`; any u16
// is OR'd into the shadow register word and later blasted to the device
// with a raw volatile write.
use std::ptr;

pub struct W {
    pub bits: u32,
}

pub struct FieldWriter<'a> {
    pub w: &'a mut W,
}

impl<'a> FieldWriter<'a> {
    // mirrors imxrt1062-dcp generated `bits(self, value)`: unchecked raw
    // insertion of the field value into the register shadow word.
    pub fn bits(self, value: u16) -> &'a mut W {
        self.w.bits = (self.w.bits & !0xffff) | ((value as u32) & 0xffff);
        self.w
    }
}

pub struct RegisterBlock {
    pub field: *mut u32,
}

impl RegisterBlock {
    pub fn write<F>(&mut self, f: F)
    where
        F: FnOnce(FieldWriter) -> &'static mut W,
    {
        // NOTE: 'static lifetime laundering mirrors svd2rust's proc-macro
        // generated W borrow trick; kept minimal here to preserve the
        // safe-looking call-site signature of `.write(|w| w.bits(v))`.
        let mut w = W { bits: 0 };
        let w_ref: &'static mut W = unsafe { &mut *(&mut w as *mut W) };
        let result = f(FieldWriter { w: w_ref });
        let bits = result.bits;
        // Raw MMIO write: no validation that `bits` encodes a legal
        // device state or that `self.field` is currently mapped/valid.
        unsafe { ptr::write_volatile(self.field, bits) }
    }
}

