// Calls the modular "safe-looking" API bits() with an out-of-range /
// unvalidated encoding that reaches the device register verbatim.
fn main() {
    // No real hardware mapped: this address stands in for an
    // unmapped/invalid MMIO region on the target device.
    let mut reg = poc_lib::RegisterBlock {
        field: 0x4000_0000 as *mut u32,
    };

    // Safe call site: no `unsafe` needed even though this drives a raw
    // volatile write of an unchecked 16-bit value into a device register.
    reg.write(|w| w.bits(0xFFFF));
}

