// Minimal reconstruction of the `coqui_stt_sys::StreamingState` FFI type and the
// `Stream::from_ptr` constructor / drop-time FFI call from the `coqui-stt` crate.

#[repr(C)]
pub struct StreamingState {
    pub data: u32,
}

pub struct Model;

pub struct Stream<'a> {
    model: &'a mut Model,
    state: *mut StreamingState,
    already_freed: bool,
}

impl<'a> Stream<'a> {
    /// # Safety
    /// Caller must ensure `state` is a valid, non-null, live pointer.
    pub unsafe fn from_ptr(model: &'a mut Model, state: *mut StreamingState) -> Stream<'a> {
        Self {
            model,
            state,
            already_freed: false,
        }
    }

    /// Mirrors the crate's `finish_stream`/`Drop` path, which dereferences
    /// the stored raw pointer to hand it back to the C library. No
    /// null/validity check is performed here, matching the real crate.
    pub fn finish(&mut self) -> u32 {
        // Simulates the FFI call `coqui_stt_sys::STT_FreeStream(self.state)` /
        // `coqui_stt_sys::STT_FinishStream(self.state, ...)` which dereferences
        // the raw pointer inside the C library.
        let val = unsafe { (*self.state).data };
        self.already_freed = true;
        val
    }
}

// SAFE wrapper: this is the crux of the bug. It builds a Stream from a
// pointer that is *not* guaranteed to be valid (it can be built from any
// integer, including one that doesn't correspond to a live allocation), yet
// this function itself contains no `unsafe` keyword requirement for the
// caller and is exposed as ordinary safe API surface a downstream user would
// call without ever writing `unsafe`.
pub fn make_stream_from_addr(model: &mut Model, addr: usize) -> Stream<'_> {
    let ptr = addr as *mut StreamingState;
    // SAFETY (library-internal only): this trusts `addr` unconditionally,
    // exactly like the real `from_ptr`, which performs no validation.
    unsafe { Stream::from_ptr(model, ptr) }
}

