    let bogus_addr: usize = 0xdead_beef;
    let mut stream = make_stream_from_addr(&mut model, bogus_addr);

    // This triggers a dereference of the invalid pointer inside the library,
    // simulating the real crate's drop/finish FFI call across the boundary.
    let val = stream.finish();
    println!("got: {}", val);
