unsafe fn unlock_shared_fast(&self) -> bool {
    // Just go to the slow path if we're not the only reader
    let state = self.state.load(Ordering::Relaxed);
    if state.address() != SINGLE_READER {
        return false;
    }

    self.state
        .compare_exchange(
            state.with_address(SINGLE_READER),
            state.with_address(UNLOCKED),
            Ordering::Release,
            Ordering::Relaxed,
        )
        .is_ok()
}

poc_lib_rs:
use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicUsize, Ordering};

const UNLOCKED: usize = 0;
const SINGLE_READER: usize = 1;
const WRITE_LOCKED: usize = usize::MAX;

pub struct RwLock<T> {
    state: AtomicUsize,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for RwLock<T> {}

pub struct ReadGuard<'a, T> {
    lock: &'a RwLock<T>,
}

pub struct WriteGuard<'a, T> {
    lock: &'a RwLock<T>,
}

impl<T> RwLock<T> {
    pub fn new(data: T) -> Self {
        Self {
            state: AtomicUsize::new(UNLOCKED),
            data: UnsafeCell::new(data),
        }
    }

    pub fn lock_shared(&self) -> ReadGuard<'_, T> {
        loop {
            let state = self.state.load(Ordering::Relaxed);
            if state == UNLOCKED
                && self
                    .state
                    .compare_exchange_weak(UNLOCKED, SINGLE_READER, Ordering::Acquire, Ordering::Relaxed)
                    .is_ok()
            {
                return ReadGuard { lock: self };
            }
            std::thread::yield_now();
        }
    }

    pub fn lock(&self) -> WriteGuard<'_, T> {
        loop {
            if self
                .state
                .compare_exchange_weak(UNLOCKED, WRITE_LOCKED, Ordering::Acquire, Ordering::Relaxed)
                .is_ok()
            {
                return WriteGuard { lock: self };
            }
            std::thread::yield_now();
        }
    }

    // Mirrors usync's `RwLock::unlock_shared_fast`: a fast-path unlock that
    // only checks the *encoded* reader count in `state`, never who is
    // calling. Upstream this is `unsafe fn`, invoked solely from
    // `ReadGuard::drop` where "self currently holds a read lock" is
    // guaranteed by construction. Exposing the same body as a *safe*
    // public method (as manual-unlock wrappers commonly do) drops that
    // invariant: any thread, holding a guard or not, can flip the lock
    // to UNLOCKED out from under a live reader.
    pub fn unlock_shared(&self) -> bool {
        let state = self.state.load(Ordering::Relaxed);
        if state != SINGLE_READER {
            return false;
        }
        self.state
            .compare_exchange(state, UNLOCKED, Ordering::Release, Ordering::Relaxed)
            .is_ok()
    }
}

impl<'a, T> std::ops::Deref for ReadGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> std::ops::Deref for WriteGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> std::ops::DerefMut for WriteGuard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.lock.data.get() }
    }
}

impl<'a, T> Drop for ReadGuard<'a, T> {
    fn drop(&mut self) {
        self.lock.unlock_shared();
    }
}

poc_main_rs:
use poc::RwLock;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let lock = Arc::new(RwLock::new(0i32));
    let l2 = Arc::clone(&lock);

    let reader = thread::spawn(move || {
        let guard = l2.lock_shared();
        for _ in 0..5 {
            // Reader believes it exclusively holds shared-read access
            // for as long as `guard` is alive.
            let _ = *guard;
            thread::sleep(Duration::from_millis(50));
        }
        drop(guard);
    });

    thread::sleep(Duration::from_millis(100));

    // Safe code calls the fast unlock path directly, without ever having
    // taken a ReadGuard itself. This wrongly transitions
    // SINGLE_READER -> UNLOCKED while `reader` is still using its guard.
    lock.unlock_shared();

    // The lock now looks free, so a writer can acquire it...
    let mut wguard = lock.lock();
    // ...and mutate the data concurrently with the reader thread above:
    // an unsynchronized concurrent read/write -> data race UB, reached
    // entirely through safe Rust in main.
    *wguard = 999;
    drop(wguard);

    reader.join().unwrap();
}

