pub struct BitVec {
    storage: Vec<u32>,
    nbits: usize,
}

impl BitVec {
    pub fn new() -> Self {
        BitVec { storage: Vec::new(), nbits: 0 }
    }

    // Raw setter: caller must ensure len <= storage.len() * 32.
    // Marked unsafe, but nothing in this module enforces the precondition
    // before it's reached from safe wrappers below.
    pub unsafe fn set_len(&mut self, len: usize) {
        self.nbits = len;
    }

    // Safe public API that forwards to set_len without validating
    // `len` against the real storage capacity: the missing check.
    pub fn grow_len(&mut self, len: usize) {
        unsafe {
            self.set_len(len);
        }
    }

    pub fn len(&self) -> usize {
        self.nbits
    }

    pub fn get(&self, index: usize) -> bool {
        let word = index / 32;
        let bit = index % 32;
        unsafe { (*self.storage.get_unchecked(word) >> bit) & 1 == 1 }
    }
}

