use std::ffi::{CStr, CString};
use std::os::raw::c_char;

pub type TractResult = i32;

// Minimal stand-ins for the real tract-ffi opaque handle types.
pub struct TractNnef(pub String);
pub struct TractModel(pub String);

macro_rules! check_not_null {
    ($($ptr:expr),+) => {
        $(
            if $ptr.is_null() {
                return -1;
            }
        )+
    };
}

fn wrap<F: FnOnce() -> Result<(), Box<dyn std::error::Error>>>(f: F) -> TractResult {
    match f() {
        Ok(()) => 0,
        Err(_) => -1,
    }
}

/// # Safety
/// `nnef` and `model` must be valid, live pointers obtained from the
/// corresponding constructors and not yet freed.
pub unsafe extern "C" fn tract_nnef_write_model_to_tar(
    nnef: *const TractNnef,
    path: *const c_char,
    model: *const TractModel,
) -> TractResult {
    wrap(|| unsafe {
        check_not_null!(nnef, model, path);
        let path = CStr::from_ptr(path).to_str()?;
        // Same root cause as tract-ffi: pointer was only null-checked, not
        // checked for liveness, so this deref can be a use-after-free.
        println!("writing model '{}' to '{}'", (*model).0, path);
        let _ = &(*nnef).0;
        Ok(())
    })
}

