pub fn create_nnef() -> *const TractNnef {
    Box::into_raw(Box::new(TractNnef("nnef-ctx".to_string())))
}

pub fn free_nnef(ptr: *const TractNnef) {
    unsafe {
        drop(Box::from_raw(ptr as *mut TractNnef));
    }
}

pub fn create_model() -> *const TractModel {
    Box::into_raw(Box::new(TractModel("model-data".to_string())))
}

pub fn safe_write(nnef: *const TractNnef, path: &str, model: *const TractModel) -> TractResult {
    let cpath = CString::new(path).unwrap();
    unsafe { tract_nnef_write_model_to_tar(nnef, cpath.as_ptr(), model) }
}

