use std::ptr;

// Minimal reconstruction of the svd2rust-style register writer proxy (W) and
// field-writer proxy, mirroring imxrt1062-csi's generated `bits()` setter.
pub struct W {
    pub bits: u32,
}

pub struct FieldW<'a> {
    w: &'a mut W,
}

impl<'a> FieldW<'a> {
    // Mirrors the real generated signature: `pub unsafe fn bits(self, value: u32) -> &'a mut W`.
    // The body performs only a masked merge into the shadow value -- no validation
    // of `value` against the field's valid encoding range, despite being unsafe.
    pub unsafe fn bits(self, value: u32) -> &'a mut W {
        self.w.bits = (self.w.bits & !0x003f_ffff) | ((value as u32) & 0x003f_ffff);
        self.w
    }
}

// A safe register handle over a raw MMIO-like pointer, mirroring how svd2rust
// register blocks expose a safe `write` that hands the user a `W` proxy and
// then commits it with `write_volatile`.
pub struct Reg {
    addr: *mut u32,
}

impl Reg {
    pub fn new(addr: *mut u32) -> Self {
        Reg { addr }
    }

    // Safe entry point (as in real svd2rust APIs, `write` itself is safe;
    // only the field setter closure argument type dictates safety).
    // Here we directly expose the unsafe field setter call internally so
    // that callers only ever touch safe code -- reproducing the pattern
    // where the crate's public surface silently swallows the `unsafe`.
    pub fn write_raw_field(&mut self, value: u32) {
        let mut w = W { bits: 0 };
        let fw = FieldW { w: &mut w };
        // SAFETY (crate-internal, not exposed to caller): this mirrors how
        // generated code sometimes wraps `unsafe { ... .bits(value) }` inside
        // a safe closure passed to `.write(|w| unsafe { w.field().bits(value) })`,
        // so the *user's* call site (in main.rs) never writes `unsafe`.
        let w_ref = unsafe { fw.bits(value) };
        unsafe {
            ptr::write_volatile(self.addr, w_ref.bits);
        }
    }
}

