pub struct FixedDeque<const N: usize> {
    data: [i32; N],
    len: usize,
}

impl<const N: usize> FixedDeque<N> {
    pub fn new() -> Self {
        FixedDeque { data: [0; N], len: 0 }
    }

    pub fn capacity(&self) -> usize {
        N
    }

    // Mirrors arraydeque's `set_len`: the only precondition check is a
    // debug_assert, which is compiled out in release builds and does not
    // stop a bogus `len` from being stored even in debug builds (it merely
    // panics after the fact rather than preventing misuse at the type level).
    unsafe fn set_len(&mut self, len: usize) {
        debug_assert!(len <= self.capacity());
        self.len = len;
    }

