// Minimal reconstruction of the essence of irondash_texture's
// GObject class instance-init callback, and the safe wrapper around it.

#[repr(C)]
pub struct GTypeInstance {
    pub g_class: *mut u8,
}

pub type Gpointer = *mut core::ffi::c_void;

// This mirrors the real target: an `unsafe extern "C"` callback that the
// GObject runtime is supposed to call ONLY with a pointer to a live,
// fully-initialized GTypeInstance (allocated via g_type_create_instance).
// It writes through the pointer, trusting that invariant.
unsafe extern "C" fn texture_gl_impl_instance_init(
    instance: *mut GTypeInstance,
    _instance_data: Gpointer,
) {
    // Real code touches fields hanging off the instance; here we simulate
    // that by writing through the pointer, which is exactly what the C
    // runtime assumes is valid for a properly constructed instance.
    (*instance).g_class = core::ptr::null_mut();
}

// Safe wrapper: this is the "modular unsafe function" -- it exposes a
// completely safe API but internally calls the unsafe FFI-style callback
// without verifying that the instance pointer it was handed is actually a
// live, properly-sized GTypeInstance allocated by the type system.
pub struct TextureGlClass;

impl TextureGlClass {
    pub fn new() -> Self {
        TextureGlClass
    }

    // Safe caller-facing API: takes a raw address as a plain integer
    // (as safe wrappers often do when bridging FFI handles/opaque ids)
    // and reinterprets it as the instance pointer, with no validation
    // that it points to a real, fully-initialized GTypeInstance.
    pub fn init_instance_at(&self, addr: usize, data: usize) {
        let instance = addr as *mut GTypeInstance;
        let instance_data = data as Gpointer;
        unsafe {
            texture_gl_impl_instance_init(instance, instance_data);
        }
    }
}

