}

impl<'a> FieldW<'a> {
    #[doc = r"Writes raw bits to the field"]
    #[inline(always)]
    pub fn bits(self, value: u8) -> &'a mut W {
        // exact body semantics of the target function: mask into the 6-bit
        // field with no validation that the resulting encoding is one the
        // CMP1 hardware actually defines (reserved encodings are UB on device).
        self.w.bits = (self.w.bits & !0x3f) | ((value as u8) & 0x3f);
        self.w
    }
}

// Mirrors the generated register block: a raw MMIO pointer into device memory.
pub struct Cmp1 {
    ctrl: *mut u8,
}

impl Cmp1 {
    // Constructs a handle to the CMP1 CTRL register at a fixed MMIO address,
    // exactly like svd2rust's generated `fn ptr()` / register block constant.
    pub fn at(addr: usize) -> Self {
        Cmp1 { ctrl: addr as *mut u8 }
    }

    // Public, *safe* entry point (mirrors svd2rust's safe `modify`/`write`
    // wrapper) that hands the caller a field proxy and then commits the
    // resulting bits straight to the device with no further checks.
    pub fn ctrl(&mut self, f: impl FnOnce(FieldW) -> &mut W) {
        let mut w = W { bits: 0 };
        f(FieldW { w: &mut w });
        unsafe { ptr::write_volatile(self.ctrl, w.bits) }
    }
}

