use poc_dm_imxrt1062_cmp1::Cmp1;

fn main() {
    // No CMP1 hardware mapped here: this models a register whose device
    // handle points at an address the process does not own (unmapped MMIO).
    let mut cmp1 = Cmp1::at(0x4000_0000);

    // Entirely safe Rust: no `unsafe` keyword anywhere in this file. The
    // out-of-range/undefined 6-bit encoding 0x3F (all field bits set, a
    // reserved CMP1 configuration) is composed through the public, safe
    // `ctrl`/`bits` API and lands as a raw volatile write to the invalid
    // device address chosen above.
    cmp1.ctrl(|w| w.bits(0xFF));
}

