use std::cmp::Ordering;
use std::ffi::CStr;
use std::os::raw::{c_char, c_int};

fn c_ordering(a: &str, b: &str) -> c_int {
    match a.cmp(b) {
        Ordering::Less => -1,
        Ordering::Equal => 0,
        Ordering::Greater => 1,
    }
}

/// # Safety
/// `s1` and `s2` must be valid, non-null, NUL-terminated, live C strings.
pub unsafe extern "C" fn po6_rt_strcmp(s1: *const c_char, s2: *const c_char) -> c_int {
    let [s1, s2] = [s1, s2].map(|str| CStr::from_ptr(str).to_str().unwrap_or_default());

    c_ordering(s1, s2)
}

/// Safe wrapper that a downstream crate might reasonably write: it takes owned
/// `CString`-like byte buffers and hands out raw pointers, but nothing ties the
/// returned pointer's lifetime to the buffer it came from, so callers can (and
/// safe Rust here does) let the buffer die before the FFI call happens.
pub fn make_c_ptr(bytes: Vec<u8>) -> *const c_char {
    // Build a NUL-terminated buffer, then leak-free-drop it: the pointer
    // returned points into a heap allocation that is immediately freed.
    let mut owned = bytes;
    owned.push(0);
    let ptr = owned.as_ptr() as *const c_char;
    // `owned` is dropped here, deallocating the buffer `ptr` points into.
    drop(owned);
    ptr
}

/// Fully safe entry point: no `unsafe` at the call site in main, but internally
/// it forwards a dangling pointer straight into the FFI boundary function.
pub fn safe_strcmp(s1: *const c_char, s2: *const c_char) -> c_int {
    unsafe { po6_rt_strcmp(s1, s2) }
}

