    // `make_c_ptr` before we ever get the pointer back.
    let p1 = make_c_ptr(b"hello".to_vec());
    let p2 = make_c_ptr(b"world".to_vec());

    // No `unsafe` here: safe_strcmp is a safe function, yet it dereferences
    // freed memory inside the FFI-facing po6_rt_strcmp, triggering UB.
    let result = safe_strcmp(p1, p2);
    println!("result = {result}");
}

