use std::cell::UnsafeCell;
use std::sync::atomic::{fence, AtomicU32, AtomicU64, Ordering};

pub const CAPACITY: usize = 4;

pub struct IndexQueue {
    head: AtomicU64,
    next_free_index: [UnsafeCell<u32>; CAPACITY],
    borrowed_indices: AtomicU32,
    data: [UnsafeCell<i64>; CAPACITY],
}

unsafe impl Sync for IndexQueue {}

impl IndexQueue {
    pub fn new() -> Self {
        let head = Self::pack_from_head_and_aba(0, 0);
        Self {
            head: AtomicU64::new(head),
            next_free_index: [
                UnsafeCell::new(1),
                UnsafeCell::new(2),
                UnsafeCell::new(3),
                UnsafeCell::new(u32::MAX),
            ],
            borrowed_indices: AtomicU32::new(0),
            data: [
                UnsafeCell::new(0),
                UnsafeCell::new(0),
                UnsafeCell::new(0),
                UnsafeCell::new(0),
            ],
        }
    }

    fn verify_init(&self, _caller: &str) {}

    fn extract_head_and_aba(v: u64) -> (u32, u32) {
        ((v & 0xFFFF_FFFF) as u32, (v >> 32) as u32)
    }

    fn pack_from_head_and_aba(head: u32, aba: u32) -> u64 {
        (head as u64) | ((aba as u64) << 32)
    }

    fn get_next_free_index(&self, index: u32) -> *mut u32 {
        self.next_free_index[index as usize].get()
    }

    // Safe convenience API used only to set up / drive the PoC; not the audited target.
    pub fn acquire_raw_index(&self) -> Option<u32> {
        self.verify_init("acquire_raw_index");
        let mut old = self.head.load(Ordering::Acquire);
        loop {
            let (old_head, old_aba) = Self::extract_head_and_aba(old);
            if old_head == u32::MAX {
                return None;
            }
            let new_head = unsafe { *self.get_next_free_index(old_head) };
            let new = Self::pack_from_head_and_aba(new_head, old_aba.wrapping_add(1));
            match self
                .head
                .compare_exchange(old, new, Ordering::AcqRel, Ordering::Acquire)
            {
                Ok(_) => {
                    self.borrowed_indices.fetch_add(1, Ordering::Relaxed);
                    return Some(old_head);
                }
                Err(v) => old = v,
            }
        }
    }

    // Safe wrapper that calls the unsafe target function with no `unsafe` required
    // at the call site in main.rs. Real-world crates expose ergonomic safe wrappers
    // like this one without tracking whether `index` is still actually borrowed.
    pub fn release(&self, index: u32) {
        unsafe { self.release_raw_index(index) };
    }

    // ---- target function (semantics preserved from iceoryx2-bb-lock-free) ----
    pub unsafe fn release_raw_index(&self, index: u32) {
        self.verify_init("release_raw_index");
        fence(Ordering::Release);

        let mut old = self.head.load(Ordering::Acquire);
        let (mut old_head, mut old_aba) = Self::extract_head_and_aba(old);

        loop {
            *self.get_next_free_index(index) = old_head;
            let new_head = index;
            let new_aba = old_aba.wrapping_add(1);
            let new = Self::pack_from_head_and_aba(new_head, new_aba);

            match self
                .head
                .compare_exchange(old, new, Ordering::AcqRel, Ordering::Acquire)
            {
                Ok(_) => {
                    self.borrowed_indices.fetch_sub(1, Ordering::Relaxed);
                    return;
                }
                Err(v) => {
                    old = v;
                    let (h, a) = Self::extract_head_and_aba(v);
                    old_head = h;
                    old_aba = a;
                }
            }
        }
    }
    // ---------------------------------------------------------------------------

    // Safe accessor into the slot "owned" by an acquired index; no unsafe keyword
    // needed at call sites, mirroring how payload access is normally exposed.
    pub fn write(&self, index: u32, value: i64) {
        unsafe {
            *self.data[index as usize].get() = value;
        }
    }
}

