    let idx = q.acquire_raw_index().expect("index available");
    q.release(idx);
    q.release(idx); // double release: no `unsafe` needed, corrupts the free list

    let q1 = Arc::clone(&q);
    let q2 = Arc::clone(&q);

    let t1 = thread::spawn(move || {
        if let Some(i) = q1.acquire_raw_index() {
            for v in 0..2000i64 {
                q1.write(i, v);
            }
            thread::sleep(Duration::from_millis(50));
        }
    });

    let t2 = thread::spawn(move || {
        if let Some(i) = q2.acquire_raw_index() {
            for v in (0..2000i64).rev() {
                q2.write(i, v);
            }
            thread::sleep(Duration::from_millis(50));
        }
    });

    t1.join().unwrap();
    t2.join().unwrap();
}

