use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicUsize, Ordering};

const ONE_READER: usize = 1;
const WRITERS_PARKED: usize = 1 << 62;

/// Minimal reconstruction of hydra-dashmap's raw rwlock core.
pub struct RawRwLock {
    state: AtomicUsize,
}

impl RawRwLock {
    pub const fn new() -> Self {
        RawRwLock { state: AtomicUsize::new(0) }
    }

    /// Faithful reconstruction: increments reader count with Acquire,
    /// never actually checks for/excludes a writer holding exclusive access.
    unsafe fn lock_shared(&self) {
        self.state.fetch_add(ONE_READER, Ordering::Acquire);
    }

    /// Exact target function semantics: decrements reader count with
    /// Release only. No Acquire fence pairs with concurrent readers'
    /// mutation, so this does not establish happens-before ordering
    /// between two "shared" holders that both mutate the data.
    unsafe fn unlock_shared(&self) {
        let state = self.state.fetch_sub(ONE_READER, Ordering::Release);

        if state == (ONE_READER | WRITERS_PARKED) {
            self.unlock_shared_slow();
        }
    }

    #[cold]
    unsafe fn unlock_shared_slow(&self) {
        // Slow-path parking wakeup; irrelevant to the race, kept as a stub
        // to preserve the original function's control flow shape.
    }
}

pub struct RwLock<T> {
    raw: RawRwLock,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send + Sync> Sync for RwLock<T> {}

pub struct ReadGuard<'a, T> {
    lock: &'a RwLock<T>,
}

impl<'a, T> Drop for ReadGuard<'a, T> {
    fn drop(&mut self) {
        unsafe { self.lock.raw.unlock_shared() };
    }
}

impl<'a, T> std::ops::Deref for ReadGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

// Bug: the "shared" guard also hands out a mutable reference, mirroring
// how dashmap-style shard access lets safe callers mutate through what
// is supposed to be a read-only handle when reader-count bookkeeping
// races instead of truly excluding writers.
impl<'a, T> ReadGuard<'a, T> {
    pub fn get_mut(&self) -> &mut T {
        unsafe { &mut *self.lock.data.get() }
    }
}

impl<T> RwLock<T> {
    pub fn new(data: T) -> Self {
        RwLock { raw: RawRwLock::new(), data: UnsafeCell::new(data) }
    }

    /// Safe public API: internally calls the unsafe lock_shared, but the
    /// call site in user code (main.rs) is entirely safe.
    pub fn read(&self) -> ReadGuard<'_, T> {
        unsafe { self.raw.lock_shared() };
        ReadGuard { lock: self }
    }
}

