use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicBool, Ordering};

pub struct DrumLock<T> {
    flag: AtomicBool,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for DrumLock<T> {}

pub struct DrumGuard<'a, T> {
    lock: &'a DrumLock<T>,
}

impl<'a, T> std::ops::Deref for DrumGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> std::ops::DerefMut for DrumGuard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.lock.data.get() }
    }
}

impl<T> DrumLock<T> {
    pub fn new(v: T) -> Self {
        DrumLock {
            flag: AtomicBool::new(false),
            data: UnsafeCell::new(v),
        }
    }

    pub fn lock(&self) -> DrumGuard<'_, T> {
        while self
            .flag
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Acquire)
            .is_err()
        {
            std::hint::spin_loop();
        }
        DrumGuard { lock: self }
    }

    // Reconstructed target function: mirrors drumbeat's `unsafe fn unlock`.
    // Body semantics preserved verbatim (just a Release store clearing the flag).
    // Exposed here through a SAFE wrapper, matching how modular-unsafe APIs
    // let safe code reach an unsafe primitive without writing `unsafe` itself.
    pub fn unlock(&self) {
        unsafe { self.raw_unlock() }
    }

    unsafe fn raw_unlock(&self) {
        self.flag.store(false, Ordering::Release);
    }
}

