use std::ffi::{c_char, CStr, CString};

pub const MAX_EXTENSION_NAME_SIZE: usize = 256;

#[repr(C)]
#[derive(Clone, Copy)]
pub struct ExtensionProperties {
    pub extension_name: [c_char; MAX_EXTENSION_NAME_SIZE],
    pub spec_version: u32,
}

pub struct Entry;

impl Entry {
    /// Simulates the FFI call `vkEnumerateInstanceExtensionProperties`.
    /// Real Vulkan loaders are assumed to always NUL-terminate `extension_name`,
    /// but nothing in the Rust type system enforces that -- if the loader/driver
    /// fills the whole 256-byte array with no NUL byte anywhere (worst case this
    /// crate never guards against), the assumption silently breaks.
    pub fn enumerate_instance_extension_properties(&self) -> Result<Vec<ExtensionProperties>, ()> {
        // No NUL byte anywhere in the struct: name bytes are all 0x01 and
        // spec_version's bytes (0x01010101) also contain no zero byte.
        let name = [1 as c_char; MAX_EXTENSION_NAME_SIZE];
        Ok(vec![ExtensionProperties {
            extension_name: name,
            spec_version: 0x0101_0101,
        }])
    }
}

/// Faithful reconstruction of sarekt's `log_extensions_dialog`.
/// SAFETY (unenforced by the type system): caller must guarantee every
/// `extension_name` in the entries returned by
/// `enumerate_instance_extension_properties` is NUL-terminated within its
/// 256-byte array, matching what the C API is assumed to do.
pub unsafe fn log_extensions_dialog(entry: &Entry, extension_names: &[&CStr]) -> Vec<CString> {
    let result: Vec<CString> = entry
        .enumerate_instance_extension_properties()
        .expect("Couldn't enumerate extensions")
        .iter_mut()
        .map(|e| CStr::from_ptr(e.extension_name.as_mut_ptr()).to_owned())
        .collect();
    let _ = extension_names;
    result
}

/// Safe public wrapper, matching how the real crate exposes this path to
/// callers without requiring `unsafe` at the call site.
pub fn safe_log_extensions_dialog(entry: &Entry, extension_names: &[&CStr]) -> Vec<CString> {
    unsafe { log_extensions_dialog(entry, extension_names) }
}

