use std::fs::OpenOptions;
use std::marker::PhantomData;
use std::mem::size_of;
use std::ops::Index;
use std::path::Path;

pub struct AmnesiMmap<T> {
    mmap: memmap2::MmapRaw,
    height: usize,
    phantom: PhantomData<T>,
}

impl<T> AmnesiMmap<T> {
    // Mirrors the real crate's target function verbatim in semantics:
    // no check that height * size_of::<T>() is nonzero / doesn't overflow,
    // and no check relating `height` to any caller-visible row count.
    unsafe fn create<P: AsRef<Path>>(path: P, height: usize) -> anyhow::Result<Self> {
        let file = OpenOptions::new()
            .read(true)
            .write(true)
            .create_new(true)
            .open(path)?;
        let width = size_of::<T>();
        let expected_size = height * width;
        file.set_len(expected_size as u64)?;
        Ok(Self {
            mmap: memmap2::MmapRaw::map_raw(&file)?,
            height,
            phantom: PhantomData,
        })
    }

    // Public, entirely safe constructor exposed by the wrapper crate.
    pub fn new<P: AsRef<Path>>(path: P, height: usize) -> anyhow::Result<Self> {
        // SAFETY (crate author's claim): caller just supplies a path and a
        // row count; there is nothing "unsafe" about that from the outside,
        // so real-world wrappers expose this as a safe fn.
        unsafe { Self::create(path, height) }
    }

    pub fn row_count(&self) -> usize {
        // The API advertises `height` rows are available, regardless of
        // whether the backing mmap was actually sized for them.
        self.height
    }
}

impl<T> Index<usize> for AmnesiMmap<T> {
    type Output = T;

    fn index(&self, row: usize) -> &T {
        assert!(row < self.height, "row out of bounds");
        let width = size_of::<T>();
        let ptr = self.mmap.as_ptr();
        unsafe { &*(ptr.add(row * width) as *const T) }
    }
}

