    // mmap) is zero-length. Nothing here uses `unsafe`.
    let map: AmnesiMmap<u64> = AmnesiMmap::new(path, 0).expect("create failed");

    // The wrapper still reports `height` rows via row_count() in real
    // usage; here we directly index row 0 through the safe Index impl,
    // which reads past the end of the zero-length mmap allocation.
    let value = map[0];
    println!("read: {}", value);

