use std::mem::MaybeUninit;

pub struct RingBuffer<T, const N: usize> {
    storage_empty: bool,
    storage_usage: usize,
    storage_slice: [MaybeUninit<T>; N],
}

impl<T, const N: usize> RingBuffer<T, N> {
    // Reconstructed verbatim from circularing's internal constructor.
    // It trusts `storage_usage` as the number of *initialized* elements
    // in `storage_slice` without verifying that invariant.
    pub const unsafe fn from_raw_parts(storage_slice: [MaybeUninit<T>; N], storage_usage: usize) -> Self {
        debug_assert!(N != 0, "buffer size was zero");

        let storage_empty = storage_usage == 0;

        Self {
            storage_empty,
            storage_usage,
            storage_slice,
        }
    }

    // Safe public constructor shipped alongside from_raw_parts. It never
    // initializes any element of storage_slice, yet reports the buffer as
    // completely full (storage_usage == N), breaking the invariant that
    // later safe accessors rely on.
    pub fn new_claiming_full() -> Self {
        let storage_slice: [MaybeUninit<T>; N] = unsafe { MaybeUninit::uninit().assume_init() };
        unsafe { Self::from_raw_parts(storage_slice, N) }
    }

    pub fn is_empty(&self) -> bool {
        self.storage_empty
    }

    pub fn len(&self) -> usize {
        self.storage_usage
    }

    // Safe accessor trusting the storage_usage invariant established by
    // from_raw_parts: slot 0 is assumed initialized whenever len() > 0.
    pub fn first(&self) -> &T {
        unsafe { self.storage_slice[0].assume_init_ref() }
    }
}

