use std::iter;
use std::mem::{transmute, MaybeUninit};

// Reconstructed minimal essence of bilrost's chunked-buffer slice iterator.
// SAFETY (upheld only if caller ensures every byte from `front` onward in the
// last chunk, and all of `rest`, is actually initialized): none checked here.
unsafe fn to_vectorable_slices(
    chunks: &[Box<[MaybeUninit<u8>]>],
    front: usize,
) -> impl Iterator<Item = &[u8]> {
    chunks
        .split_last()
        .into_iter()
        .flat_map(move |(front_chunk, rest)| {
            iter::once(&front_chunk[front..]).chain(rest.iter().rev().map(Box::as_ref))
        })
        // SAFETY: the portion of the front chunk after `front` that we have sliced, and every chunk
        // after that, are all valid bytes.
        .map(|m| unsafe { transmute::<&[MaybeUninit<u8>], &[u8]>(m) })
}

// Safe public wrapper mirroring how bilrost exposes this internally: it lets
// a safe caller pick `front` with no verification that bytes are initialized.
pub struct ChunkBuf {
    chunks: Vec<Box<[MaybeUninit<u8>]>>,
}

impl ChunkBuf {
    pub fn new() -> Self {
        ChunkBuf { chunks: Vec::new() }
    }

    // Adds a chunk of `len` bytes that is entirely uninitialized.
    pub fn push_uninit_chunk(&mut self, len: usize) {
        let boxed: Box<[MaybeUninit<u8>]> = (0..len).map(|_| MaybeUninit::uninit()).collect();
        self.chunks.push(boxed);
    }

    // Safe entry point: no unsafe keyword needed at call site, yet `front` is
    // never validated against what has actually been initialized.
    pub fn readable_slices(&self, front: usize) -> Vec<u8> {
        let iter = unsafe { to_vectorable_slices(&self.chunks, front) };
        let mut out = Vec::new();
        for s in iter {
            out.extend_from_slice(s);
        }
        out
    }
}

