use poc_lib::ChunkBuf;

fn main() {
    let mut buf = ChunkBuf::new();
    // Entire chunk is uninitialized memory.
    buf.push_uninit_chunk(8);

    // Safe caller passes front = 0: nothing stops this, but it means the
    // "already sliced past front" invariant the unsafe transmute relies on
    // is violated -- every byte here is uninitialized.
    let data = buf.readable_slices(0);

    println!("{:?}", data);
}

