use std::marker::PhantomData;
use std::ptr;

pub trait RegisterSpec {
    type Ux: Copy;
}

pub struct Reg32;
impl RegisterSpec for Reg32 {
    type Ux = u32;
}

pub trait FieldSpec {
    type Ux: Copy + Into<u32>;
}

// A 4-bit field whose only valid encodings are 0..=2 (device-defined subset),
// but the field's raw type is a full u8 -- svd2rust cannot express that
// narrower invariant in the type system.
pub struct FieldA;
impl FieldSpec for FieldA {
    type Ux = u8;
}

pub trait Width {
    fn mask() -> u32;
}
pub struct Wi4;
impl Width for Wi4 {
    fn mask() -> u32 {
        0x0F
    }
}

pub struct W<REG: RegisterSpec> {
    pub bits: u32,
    pub addr: *mut u32,
    _marker: PhantomData<REG>,
}

impl<REG: RegisterSpec> W<REG> {
    pub fn new(addr: *mut u32) -> Self {
        W { bits: 0, addr, _marker: PhantomData }
    }

    // Safe sink: commits the accumulated bit pattern to the memory-mapped
    // register. No unsafe at the call site.
    pub fn write_out(&self) {
        unsafe { ptr::write_volatile(self.addr, self.bits) }
    }
}

pub struct FieldWriter<'a, REG: RegisterSpec, FI: FieldSpec, WI: Width> {
    w: &'a mut W<REG>,
    offset: u32,
    _f: PhantomData<FI>,
    _wi: PhantomData<WI>,
}

impl<'a, REG: RegisterSpec, FI: FieldSpec, WI: Width> FieldWriter<'a, REG, FI, WI> {
    pub fn new(w: &'a mut W<REG>, offset: u32) -> Self {
        FieldWriter { w, offset, _f: PhantomData, _wi: PhantomData }
    }

    // === TARGET FUNCTION (ch643 svd2rust field writer) ===
    // Writes a raw, unvalidated value into the field's bit range. Marked
    // `unsafe` because the caller must (by convention only) guarantee the
    // value is a valid encoding -- the type system enforces nothing.
    pub unsafe fn bits(self, value: FI::Ux) -> &'a mut W<REG> {
        self.w.bits &= !(WI::mask() << self.offset);
        self.w.bits |= (value.into() & WI::mask()) << self.offset;
        self.w
    }

    // A thin "ergonomic" wrapper of the kind PAC/HAL crates commonly ship
    // alongside the raw unsafe setter (e.g. for fields treated as "plain
    // numeric" instead of enumerated). It forwards straight into the unsafe
    // primitive without validating the value, so it is safe to call yet
    // carries the exact same footgun -- this is the modular-unsafe surface.
    pub fn bits_unchecked(self, value: FI::Ux) -> &'a mut W<REG> {
        unsafe { self.bits(value) }
    }
}

