    // that is not backed by any allocation.
    let mut w: W<Reg32> = W::new(0x4000_0000 as *mut u32);

    let fw: FieldWriter<Reg32, FieldA, Wi4> = FieldWriter::new(&mut w, 4);

    // Purely safe code: only 0..=2 are valid encodings for this field, but
    // nothing stops us from passing 0xFF. The safe wrapper forwards it
    // straight into the raw unsafe bit-setter.
    fw.bits_unchecked(0xFF);

    // Safe call: commits the corrupted bit pattern to the "device" via a
    // volatile write to an unmapped address -> undefined behavior.
    w.write_out();
}

