use std::alloc::{alloc, Layout};
use std::ptr::NonNull;

pub struct RawMem {
    pub ptr: NonNull<u8>,
    pub layout: Layout,
}

pub struct AnyVecLike {
    mem: RawMem,
    size: usize,
    element_layout: Layout,
}

impl AnyVecLike {
    // Faithful reconstruction of any_vec's AnyVecRaw::from_raw_parts:
    // it just stores whatever `size` and `element_layout` the caller hands it,
    // with no check that `mem` actually holds `size` initialized elements
    // of `element_layout`'s size/alignment.
    unsafe fn from_raw_parts(handle: RawMem, element_layout: Layout, size: usize) -> Self {
        Self {
            mem: handle,
            size,
            element_layout,
        }
    }

    // Safe-looking public constructor a downstream crate would expose,
    // e.g. "create a typed vector view over a fresh allocation".
    // It allocates memory for zero elements but is careless about
    // propagating that zero size into the logical `size` field.
    pub fn new_with_capacity<T>(claimed_len: usize) -> Self {
        let element_layout = Layout::new::<T>();
        // Allocate only enough for 0 elements (bug: real cap ignored,
        // caller-controlled claimed_len is trusted instead).
        let alloc_layout = Layout::from_size_align(0, element_layout.align().max(1)).unwrap();
        let ptr = unsafe {
            let raw = alloc(alloc_layout.pad_to_align());
            NonNull::new(raw).unwrap_or(NonNull::dangling())
        };
        let mem = RawMem { ptr, layout: alloc_layout };
        // This call itself is `unsafe fn`, but it's invoked from inside
        // this safe wrapper, so no `unsafe` keyword is needed at any
        // call site in a downstream safe caller.
        unsafe { Self::from_raw_parts(mem, element_layout, claimed_len) }
    }

    // Safe API surface: reading an element trusts `self.size` and the
    // allocation matching it, per the module's own invariant.
    pub fn get_u64(&self, index: usize) -> u64 {
        assert!(index < self.size, "index out of logical bounds");
        let elem_size = self.element_layout.size();
        unsafe {
            let p = self.mem.ptr.as_ptr().add(index * elem_size) as *const u64;
            std::ptr::read(p)
        }
    }
}

