use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicU32, Ordering};

const WRITE_LOCKED: u32 = 1 << 31;

pub struct RwLock<T> {
    state: AtomicU32,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for RwLock<T> {}

pub struct ReadGuard<'a, T> {
    lock: &'a RwLock<T>,
}

pub struct WriteGuard<'a, T> {
    lock: &'a RwLock<T>,
}

impl<T> RwLock<T> {
    const READ_LOCKED: u32 = 1;

    pub fn new(data: T) -> Self {
        Self { state: AtomicU32::new(0), data: UnsafeCell::new(data) }
    }

    fn num_readers(state: u32) -> u32 {
        state & !WRITE_LOCKED
    }

    fn worker_id(state: u32) -> Option<u32> {
        if state & WRITE_LOCKED != 0 { Some(0) } else { None }
    }

    pub fn read(&self) -> ReadGuard<'_, T> {
        loop {
            let state = self.state.load(Ordering::Acquire);
            if state & WRITE_LOCKED == 0 {
                if self
                    .state
                    .compare_exchange(state, state + Self::READ_LOCKED, Ordering::Acquire, Ordering::Acquire)
                    .is_ok()
                {
                    return ReadGuard { lock: self };
                }
            }
            std::thread::yield_now();
        }
    }

    pub fn write(&self) -> WriteGuard<'_, T> {
        loop {
            if self
                .state
                .compare_exchange(0, WRITE_LOCKED, Ordering::Acquire, Ordering::Acquire)
                .is_ok()
            {
                return WriteGuard { lock: self };
            }
            std::thread::yield_now();
        }
    }

    // --- target function (semantics kept as given) ---
    unsafe fn unlock_read(&self) -> u32 {
        let previous = self.state.fetch_sub(Self::READ_LOCKED, Ordering::Release);

        debug_assert!(
            Self::num_readers(previous) > 0,
            "there must have been a pending read lock"
        );
        debug_assert_eq!(
            Self::worker_id(previous),
            None,
            "cannot have a pending write lock when unlocking a read lock"
        );
        Self::num_readers(previous) - 1
    }

    fn unlock_write(&self) {
        self.state.store(0, Ordering::Release);
    }

    /// Modular-unsafe flaw: this safe wrapper forwards to the internal
    /// `unsafe fn unlock_read` with no way to verify the caller actually
    /// owns a live `ReadGuard`, so safe code can release a read lock that
    /// another thread's guard is still using.
    pub fn force_unlock_read(&self) {
        unsafe {
            self.unlock_read();
        }
    }
}

impl<'a, T> std::ops::Deref for ReadGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> Drop for ReadGuard<'a, T> {
    fn drop(&mut self) {
        unsafe {
            self.lock.unlock_read();
        }
    }
}

impl<'a, T> std::ops::Deref for WriteGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> std::ops::DerefMut for WriteGuard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.lock.data.get() }
    }
}

impl<'a, T> Drop for WriteGuard<'a, T> {
    fn drop(&mut self) {
        self.lock.unlock_write();
    }
}

