use pargraph_poc::RwLock;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let lock = Arc::new(RwLock::new(0i32));
    let l2 = Arc::clone(&lock);

    let reader = thread::spawn(move || {
        let guard = l2.read();
        // Simulate a long-lived read: repeatedly access the data while
        // still holding the ReadGuard.
        for _ in 0..5 {
            thread::sleep(Duration::from_millis(200));
            let _ = *guard;
        }
    });

    thread::sleep(Duration::from_millis(100));

    // Purely safe code releases the read lock that `reader` is still using.
    lock.force_unlock_read();

    // The reader count is now back to 0, so `write` succeeds even though
    // `reader` still holds its ReadGuard and is dereferencing the data.
    let mut wguard = lock.write();
    *wguard = 42; // unsynchronized concurrent write vs. reader's read -> UB

    drop(wguard);
    reader.join().unwrap();
}

