use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::thread::{self, Thread};

const EXCLUSIVE_FLAG: usize = 1 << (usize::BITS - 1);
const PARKED_FLAG: usize = 1 << (usize::BITS - 2);

/// Minimal reconstruction of cryo's reader/owner-exclusive lock.
/// `owner` is the thread that will eventually reclaim exclusive `&mut T`
/// access once all shared borrows created via `lock_shared` are released.
pub struct Cryo<T> {
    data: UnsafeCell<T>,
    count: AtomicUsize,
    owner: Thread,
}

unsafe impl<T: Sync> Sync for Cryo<T> {}

pub struct SharedGuard<'a, T> {
    cryo: &'a Cryo<T>,
}

impl<'a, T> std::ops::Deref for SharedGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.cryo.data.get() }
    }
}

impl<'a, T> Drop for SharedGuard<'a, T> {
    fn drop(&mut self) {
        unsafe { self.cryo.unlock_shared() };
    }
}

impl<T> Cryo<T> {
    pub fn new(data: T) -> Self {
        Cryo {
            data: UnsafeCell::new(data),
            count: AtomicUsize::new(0),
            owner: thread::current(),
        }
    }

    pub fn lock_shared(&self) -> SharedGuard<'_, T> {
        self.count.fetch_add(1, Ordering::Acquire);
        SharedGuard { cryo: self }
    }

    /// SAFE public wrapper around the internal unsafe unlock path.
    /// Nothing here checks that the caller actually owns a `SharedGuard`,
    /// so safe code can invoke it at any time to decrement the count.
    /// This is the modular-unsafe-function bug: an `unsafe fn` whose
    /// invariant ("only call once per outstanding guard, from guard drop")
    /// is not enforced by its safe entry point.
    pub fn unlock_shared_manual(&self) {
        unsafe { self.unlock_shared() };
    }

    // Target function (kept verbatim in semantics), reconstructed from cryo.
    unsafe fn unlock_shared(&self) {
        const PARKED_FLAG_P1: usize = 1 | PARKED_FLAG;
        match self.count.fetch_sub(1, Ordering::Release) {
            PARKED_FLAG_P1 => {
                // The owner thread is parked waiting for the last reader.
                self.count.store(0, Ordering::Relaxed);
                self.owner.unpark();
            }
            old_count => {
                debug_assert!((old_count & EXCLUSIVE_FLAG) == 0);
            }
        }
    }

    /// Owner-only: block until all shared borrows are released, then
    /// obtain exclusive `&mut T` access.
    pub fn lock_exclusive(&self) -> &mut T {
        loop {
            match self.count.compare_exchange(
                0,
                EXCLUSIVE_FLAG,
                Ordering::Acquire,
                Ordering::Relaxed,
            ) {
                Ok(_) => break,
                Err(_) => {
                    self.count.fetch_or(PARKED_FLAG, Ordering::Relaxed);
                    thread::park();
                }
            }
        }
        unsafe { &mut *self.data.get() }
    }
}

poc_main_rs:
use poc_lib::Cryo;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    // Owner (main) creates the lock; it is the thread recorded as `owner`.
    let cryo = Arc::new(Cryo::new(0i32));

    // Thread 2 takes a real shared borrow and keeps reading through it
    // for a while, simulating an in-progress concurrent reader.
    let c2 = Arc::clone(&cryo);
    let reader = thread::spawn(move || {
        let guard = c2.lock_shared();
        for _ in 0..2_000_000u64 {
            let _ = *guard; // concurrent read of shared data
        }
        thread::sleep(Duration::from_millis(300));
        drop(guard);
    });

    // Thread 3 is the "safe API misuse": it calls the public safe unlock
    // wrapper without ever holding a SharedGuard of its own, faking the
    // release of the reader that is still alive in `reader`.
    let c3 = Arc::clone(&cryo);
    let misuser = thread::spawn(move || {
        thread::sleep(Duration::from_millis(150));
        c3.unlock_shared_manual(); // no `unsafe` needed here: fully safe Rust
    });

    // Give the reader thread time to actually acquire its shared guard
    // before we try to reclaim exclusive access.
    thread::sleep(Duration::from_millis(50));

    // Main blocks/parks here (count == 1, so CAS fails), waiting for the
    // real shared guard to drop. But `misuser`'s premature unlock hits
    // the PARKED_FLAG_P1 fast path and unparks us early.
    let data = cryo.lock_exclusive();
    for i in 0..2_000_000i32 {
        *data = i; // concurrent write while `reader` thread still holds &T
    }

    reader.join().unwrap();
    misuser.join().unwrap();
    println!("done: {}", *data);
}

