// Minimal reconstruction of beetle-nonzero's NonZero wrapper: a generic
// newtype that relies on `new_unchecked` never being called with a zero
// value. The crate marks the inner field as carrying a non-zero invariant
// via the standard library's `NonZeroU32`, which the compiler uses for
// niche-optimization of `Option<Wrapper>`.

use std::num::NonZeroU32;

#[repr(transparent)]
pub struct NonZero<T> {
    value: T,
}

pub trait Primitive: Copy {
    fn is_zero(&self) -> bool;
}

impl Primitive for NonZeroU32Repr {
    fn is_zero(&self) -> bool {
        self.0 == 0
    }
}

// Stand-in for the crate's underlying representation: a bare u32 that is
// supposed to always be non-zero once wrapped, matching layout with
// NonZeroU32 for the niche optimization.
#[derive(Copy, Clone)]
#[repr(transparent)]
pub struct NonZeroU32Repr(pub u32);

impl<T: Primitive> NonZero<T> {
    /// # Safety
    /// `value` must satisfy the non-zero invariant.
    pub const unsafe fn new_unchecked(value: T) -> Self {
        Self { value }
    }

    // Safe public constructor exposed by the crate that forwards user
    // input straight into the unsafe constructor WITHOUT checking it,
    // making the whole call chain safe-looking from `main`.
    pub fn from_u32_unchecked_but_safe_api(value: T) -> Self {
        unsafe { Self::new_unchecked(value) }
    }

    pub fn get(&self) -> T {
        self.value
    }
}

// Use the real std NonZeroU32 internally to get genuine niche optimization
// UB when the invariant is violated via transmute-free but layout-trusting
// code path.
pub fn make_option_nonzero(v: u32) -> Option<NonZeroU32> {
    // SAFETY (supposedly, per the module's contract): caller guarantees v != 0.
    // This mirrors `new_unchecked`'s body semantics exactly: no validation,
    // straight construction of a value the compiler assumes is non-zero.
    Some(unsafe { NonZeroU32::new_unchecked(v) })
}

