    // violates the documented precondition of `new_unchecked`
    // (`NonZeroU32::new_unchecked` requires a non-zero value), but the
    // library performs no validation before calling it.
    let bad = poc_lib::make_option_nonzero(0);

    // The compiler assumes any NonZeroU32 inside is never 0 for the niche
    // optimization of Option<NonZeroU32>. Reading it back and comparing
    // triggers UB because the in-memory bit pattern (0) is invalid for the
    // type, and Miri flags the construction itself as producing an invalid
    // value.
    if let Some(n) = bad {
