// Minimal reconstruction of an svd2rust-style KPP register write path from imxrt1062-kpp.
// W mirrors the register's write proxy; `bits` holds the shadow value that gets
// committed to the real MMIO register.
use std::ptr;

pub struct W {
    pub bits: u16,
    pub reg_ptr: *mut u16,
}

pub struct FieldWriter<'a> {
    pub w: &'a mut W,
}

impl<'a> FieldWriter<'a> {
    // Mirrors the target function's body semantics exactly (0xff << 8 field, 8-bit value).
    // No validation is performed on `value`: any u8 is accepted and merged into the
    // register shadow, which is later flushed to the real device register.
    pub fn bits(self, value: u8) -> &'a mut W {
        self.w.bits = (self.w.bits & !(0xff << 8)) | (((value as u16) & 0xff) << 8);
        self.w
    }
}

impl W {
    pub fn field(&mut self) -> FieldWriter<'_> {
        FieldWriter { w: self }
    }

    // Commits the shadow register value to the mapped (here: intentionally invalid) MMIO address.
    // This is the "device write" step a real PAC performs when the register block is written.
    pub fn commit(&self) {
        unsafe { ptr::write_volatile(self.reg_ptr, self.bits) }
    }
}

pub struct RegisterBlock {
    pub reg_ptr: *mut u16,
}

impl RegisterBlock {
    // Safe entry point exposed to users: no `unsafe` keyword required at the call site,
    // even though it ultimately drives a raw pointer write with a caller-controlled,
    // unchecked value.
    pub fn write<F>(&mut self, f: F)
    where
        F: FnOnce(&mut W) -> &mut W,
    {
        let mut w = W {
            bits: 0,
            reg_ptr: self.reg_ptr,
        };
        f(&mut w);
        w.commit();
    }
}

