use poc_lib::RegisterBlock;

fn main() {
    // No hardware mapped: the "register" points at an unmapped/invalid MMIO address,
    // just like a real device register would be if driven with an out-of-range encoding.
    let mut kpp = RegisterBlock {
        reg_ptr: 0x4000_0000 as *mut u16,
    };

    // Purely safe Rust: no `unsafe` block appears here, yet an arbitrary, unvalidated
    // 8-bit value (0xFF, outside the device's valid field encodings) is written straight
    // through to the raw register pointer inside the library.
    kpp.write(|w| w.field().bits(0xFF));
}

