#![allow(dead_code)]

use core::marker::PhantomData;
use core::ptr;

// Minimal svd2rust-style register infrastructure.
pub trait RegisterSpec {
    type Ux: Copy + Default;
    type Writer: From<W<Self>>;
}

pub struct W<REG: RegisterSpec> {
    pub bits: REG::Ux,
    pub _reg: PhantomData<REG>,
}

// Concrete register description for our one device register.
pub struct REGSPEC;
impl RegisterSpec for REGSPEC {
    type Ux = u32;
    type Writer = Writer;
}

pub struct Writer {
    w: W<REGSPEC>,
}

impl From<W<REGSPEC>> for Writer {
    fn from(w: W<REGSPEC>) -> Self {
        Writer { w }
    }
}

impl Writer {
    // Root cause (DM): raw, unchecked field write -- svd2rust `bits()` accessor.
    // Any u32 is accepted and stored verbatim, no encoding/range validation.
    pub fn bits(&mut self, value: u32) -> &mut W<REGSPEC> {
        self.w.bits = value;
        &mut self.w
    }
}

pub struct Reg<REG: RegisterSpec<Ux = u32>> {
    addr: *mut u32,
    _reg: PhantomData<REG>,
}

impl<REG: RegisterSpec<Ux = u32>> Reg<REG> {
    fn set(&self, bits: u32) {
        // Models the vcell/volatile MMIO write performed by `self.register.set(...)`.
        unsafe { ptr::write_volatile(self.addr, bits) }
    }

    // Faithful port of ch32v30x's `Reg::write_with_zero` (kept `unsafe`, same body
    // semantics: seed the writer with zero, run the closure, commit `.bits` raw).
    pub unsafe fn write_with_zero<F>(&self, f: F)
    where
        F: FnOnce(&mut REG::Writer) -> &mut W<REG>,
    {
        self.set(
            (*f(&mut REG::Writer::from(W {
                bits: REG::Ux::default(),
                _reg: PhantomData,
            })))
            .bits,
        );
    }
}

impl Reg<REGSPEC> {
    pub fn new(addr: usize) -> Self {
        Reg {
            addr: addr as *mut u32,
            _reg: PhantomData,
        }
    }

    // SAFE public PAC-style wrapper (mirrors how generated crates expose
    // `write()`/`modify()` as safe functions on top of `write_with_zero`).
    // It upholds NO invariant on `value`: any u32 the caller supplies is
    // forwarded straight through the unchecked `bits()` field setter and
    // committed to the device register.
    pub fn write_raw(&self, value: u32) {
        unsafe {
            self.write_with_zero(|w: &mut Writer| w.bits(value));
        }
    }
}

