use std::mem::MaybeUninit;

/// Minimal reconstruction of tensorgraph-sys's buffer type, backed by a boxed
/// slice of `MaybeUninit<T>` plus a logical `len` that is trusted, not verified.
pub struct Buffer<T> {
    buf: Box<[MaybeUninit<T>]>,
    len: usize,
}

impl<T> Buffer<T> {
    /// Faithful reconstruction of the target function's semantics:
    /// it blindly stores whatever `len` the caller provides, with no
    /// check that `len <= buf.len()` or that the first `len` elements
    /// of `buf` are actually initialized.
    pub unsafe fn from_raw_parts(buf: Box<[MaybeUninit<T>]>, len: usize) -> Self {
        Self { buf, len }
    }

    /// Safe constructor a downstream crate would plausibly expose: allocate
    /// an uninitialized backing buffer of the requested capacity and wrap it
    /// via the unsafe primitive above. This function itself takes no unsafe
    /// input from the caller, so callers never need `unsafe` to reach UB.
    pub fn with_capacity(cap: usize) -> Self {
        let mut v: Vec<MaybeUninit<T>> = Vec::with_capacity(cap);
        // SAFETY (module-internal): MaybeUninit<T> needs no initialization,
        // so setting len to the full capacity is fine for the Vec itself.
        unsafe { v.set_len(cap) };
        let buf = v.into_boxed_slice();
        // BUG: passes `len = cap` even though none of the `cap` slots have
        // been initialized with a real `T`. `from_raw_parts` performs no
        // check tying `len` to actual initialization state.
        unsafe { Self::from_raw_parts(buf, cap) }
    }

    /// Safe accessor that trusts `self.len`, exposing the uninitialized
    /// memory as if it were valid `T`s -- this is where UB actually fires.
    pub fn as_slice(&self) -> &[T] {
        let init = &self.buf[..self.len];
        // SAFETY (module-internal, relies on the invariant that the first
        // `len` elements are initialized -- an invariant `from_raw_parts`
        // never actually established).
        unsafe { std::slice::from_raw_parts(init.as_ptr() as *const T, self.len) }
    }
}

