use poc_lib::Mutex;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let m = Arc::new(Mutex::new(0i32));
    let m2 = Arc::clone(&m);

    let h = thread::spawn(move || {
        let mut guard = m2.lock();
        for i in 0..1_000_000i32 {
            *guard = i; // still holding the guard, writing the whole time
        }
    });

    thread::sleep(Duration::from_millis(50));

    // Safe call: no `unsafe` keyword here, yet this force-unlocks the mutex
    // while the spawned thread's MutexGuard is still alive and writing.
    m.unlock();

    // Lock is now free again from main's point of view; acquire it and write,
    // concurrently with the other thread that still believes it holds the lock.
    let mut guard2 = m.lock();
    for i in 0..1_000_000i32 {
        *guard2 += i; // unsynchronized concurrent access to the same UnsafeCell
    }

    let _ = h.join();
}

