pub struct AStack<T, const N: usize> {
    items: [MaybeUninit<T>; N],
    len: usize,
}

impl<T, const N: usize> AStack<T, N> {
    // Target function: reconstructed with same semantics as astack's
    // `from_raw_parts`. Only a debug_assert protects the len <= N invariant.
    pub const unsafe fn from_raw_parts(items: [mem::MaybeUninit<T>; N], len: usize) -> Self {
        debug_assert!(len <= N);
        Self { items, len }
