        // len = 0 satisfies the invariant at construction time.
        unsafe { Self::from_raw_parts(MaybeUninit::uninit().assume_init(), 0) }
    }

    // A safe modular API that fails to re-validate the len <= N invariant
    // established by from_raw_parts, silently letting it be broken later.
    pub fn set_len(&mut self, len: usize) {
        self.len = len;
    }

    // Safe accessor that trusts `len <= N` (the invariant from_raw_parts
    // was supposed to guarantee) to build a slice over the backing array.
    pub fn as_slice(&self) -> &[T] {
        unsafe { slice::from_raw_parts(self.items.as_ptr() as *const T, self.len) }
    }
}

