use std::alloc::{alloc, dealloc, Layout};
use std::sync::Arc;

pub enum HBufDestructorInfo {
    Destructor(fn(*mut u8, usize)),
}

pub struct HBufDestructor {
    data: *mut u8,
    size: usize,
    info: HBufDestructorInfo,
}

impl HBufDestructor {
    pub fn new(data: *mut u8, size: usize, info: HBufDestructorInfo) -> HBufDestructor {
        HBufDestructor { data, size, info }
    }
}

impl Drop for HBufDestructor {
    fn drop(&mut self) {
        match self.info {
            HBufDestructorInfo::Destructor(f) => f(self.data, self.size),
        }
    }
}

pub struct HBuf {
    data_ptr: *mut u8,
    pub capacity: usize,
    pub limit: usize,
    pub position: usize,
    destructor: Arc<Option<HBufDestructor>>,
}

fn default_free(ptr: *mut u8, size: usize) {
    // Frees `size` bytes at `ptr`, trusting the caller's bookkeeping.
    unsafe {
        let layout = Layout::from_size_align(size, 1).unwrap();
        dealloc(ptr, layout);
    }
}

impl HBuf {
    // Mirrors the real crate's raw constructor: takes the invariant
    // (data, size) on faith with no way for callers to verify it.
    pub unsafe fn from_raw_parts_with_destructor(
        data: *mut u8,
        size: usize,
        destructor: fn(*mut u8, usize),
    ) -> HBuf {
        HBuf {
            data_ptr: data,
            capacity: size,
            limit: size,
            position: 0,
            destructor: Arc::new(Some(HBufDestructor::new(
                data,
                size,
                HBufDestructorInfo::Destructor(destructor),
            ))),
        }
    }

    // SAFE public wrapper, analogous to the crate's safe `new`-style
    // helpers that call the unsafe raw constructor internally without
    // validating that `logical_size` matches the real allocation size.
    pub fn new_mismatched(logical_size: usize) -> HBuf {
        // Allocates a ZST-sized (0-byte) buffer regardless of logical_size,
        // exactly the kind of length/capacity mismatch a safe caller can
        // trigger purely through public, safe-looking APIs.
        let real_alloc_size = 0usize;
        let layout = Layout::from_size_align(real_alloc_size.max(1), 1).unwrap();
        let ptr = unsafe { alloc(layout) };
        unsafe { HBuf::from_raw_parts_with_destructor(ptr, logical_size, default_free) }
    }
}

