use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicBool, Ordering};

/// Minimal reconstruction of irq's `wants_to_enter` flag based lock.
/// Only a single index (0) is modeled since the PoC needs just one flag.
pub struct IrqLock<T> {
    wants_to_enter: [AtomicBool; 1],
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for IrqLock<T> {}

pub struct IrqGuard<'a, T> {
    lock: &'a IrqLock<T>,
}

impl<'a, T> std::ops::Deref for IrqGuard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> std::ops::DerefMut for IrqGuard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.lock.data.get() }
    }
}

impl<T> IrqLock<T> {
    pub fn new(data: T) -> Self {
        IrqLock {
            wants_to_enter: [AtomicBool::new(false)],
            data: UnsafeCell::new(data),
        }
    }

    /// Safe wrapper mirroring the crate's enter path: tries to claim the
    /// single critical-section flag via compare_exchange.
    pub fn try_lock(&self, index: u8) -> Option<IrqGuard<'_, T>> {
        if self.wants_to_enter[usize::from(index)]
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Acquire)
            .is_ok()
        {
            Some(IrqGuard { lock: self })
        } else {
            None
        }
    }

    /// Exact semantics of the target function `unsafe fn unlock`, but exposed
    /// as a SAFE method (this is the modular-unsafe-function bug): safe code
    /// can call it at any time, independent of whether it currently holds
    /// the guard, releasing the flag out from under a concurrent holder.
    pub fn unlock(&self, index: u8) {
        self.wants_to_enter[usize::from(index)].store(false, Ordering::Release);
    }
}

poc_main_rs:
use irq_poc::IrqLock;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let lock = Arc::new(IrqLock::new(0i32));
    let l2 = Arc::clone(&lock);

    let h = thread::spawn(move || {
        let mut guard = l2.try_lock(0).expect("first lock should succeed");
        for i in 0..1_000_000 {
            *guard = i; // unsynchronized write, racing with main's writes below
            thread::sleep(Duration::from_micros(1));
        }
    });

    thread::sleep(Duration::from_millis(10));

    // Safe code calls the safe wrapper around the target `unlock` function
    // WITHOUT ever having successfully acquired the lock itself, releasing
    // the flag while the spawned thread's guard is still alive.
    lock.unlock(0);

    if let Some(mut guard2) = lock.try_lock(0) {
        for i in 0..1_000_000 {
            *guard2 = -i; // concurrent unsynchronized access -> data race UB
        }
    }

    h.join().unwrap();
}

