use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicBool, Ordering};

pub struct RawLock<T> {
    is_locked: AtomicBool,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for RawLock<T> {}

pub struct Guard<'a, T> {
    lock: &'a RawLock<T>,
}

impl<'a, T> std::ops::Deref for Guard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> std::ops::DerefMut for Guard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.lock.data.get() }
    }
}

impl<T> RawLock<T> {
    pub fn new(val: T) -> Self {
        Self {
            is_locked: AtomicBool::new(false),
            data: UnsafeCell::new(val),
        }
    }

    // Spins until it can flip the flag false->true (Acquire), then hands out
    // a guard giving exclusive access to `data`.
    pub fn lock(&self) -> Guard<'_, T> {
        while self
            .is_locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Acquire)
            .is_err()
        {
            std::hint::spin_loop();
        }
        Guard { lock: self }
    }

    // This mirrors happylock's `force_unlock`: it is declared `unsafe` in the
    // real crate, but nothing in the public API actually prevents a safe
    // wrapper/caller from invoking it without holding the guard. It simply
    // clears the flag, releasing the lock out from under whoever currently
    // holds it.
    pub unsafe fn force_unlock(&self) {
        self.is_locked.store(false, Ordering::Release);
    }

    // Safe-looking convenience wrapper that a downstream crate might expose,
    // exactly like happylock's own callers do internally -- this is the
    // "modular unsafe function" surface: safe signature, unsafe body.
    pub fn safe_force_unlock(&self) {
        unsafe { self.force_unlock() };
    }
}

poc_main_rs:
use poc_lib::RawLock;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let lock = Arc::new(RawLock::new(0i64));
    let l1 = lock.clone();
    let l2 = lock.clone();

    let h1 = thread::spawn(move || {
        let mut guard = l1.lock();
        for i in 0..1_000_000i64 {
            *guard = i;
        }
        thread::sleep(Duration::from_millis(200));
    });

    thread::sleep(Duration::from_millis(50));

    // l2 never called lock(); it just forces the flag false while h1's
    // guard is still alive and still writing.
    l2.safe_force_unlock();

    let h2 = thread::spawn(move || {
        let mut guard = l2.lock();
        for i in 0..1_000_000i64 {
            *guard = -i;
        }
    });

    h1.join().unwrap();
    h2.join().unwrap();
}

