use std::any::TypeId;
use std::mem::MaybeUninit;

pub struct ValueRef<'a> {
    bytes: &'a [MaybeUninit<u8>],
    type_id: TypeId,
}

impl<'a> ValueRef<'a> {
    // Mirrors dync's `from_raw_parts`: takes possibly-uninitialized bytes
    // and a type_id with no check that `bytes` actually holds a valid,
    // initialized value of that type. Marked safe here (as the module's
    // public safe wrappers ultimately allow), matching the paper's claim
    // that the invariant crosses an unsafe boundary without a runtime check.
    pub fn from_raw_parts(bytes: &'a [MaybeUninit<u8>], type_id: TypeId) -> ValueRef<'a> {
        ValueRef { bytes, type_id }
    }

    // Safe-looking accessor that later code (originally gated behind
    // `unsafe` internals) relies on `bytes` being init for `type_id`.
    pub fn get<T: 'static + Copy>(&self) -> T {
        assert_eq!(self.type_id, TypeId::of::<T>());
        assert_eq!(self.bytes.len(), std::mem::size_of::<T>());
        // SAFETY (assumed by the module): bytes are init because the
        // caller supposedly only builds ValueRef from initialized data.
        // This is the invariant safe callers can break.
        unsafe { std::ptr::read(self.bytes.as_ptr() as *const T) }
    }
}

