use poc_lib::ValueRef;
use std::any::TypeId;
use std::mem::MaybeUninit;

fn main() {
    // Uninitialized backing storage: no unsafe keyword needed to create this.
    let uninit_bytes: [MaybeUninit<u8>; 8] = [MaybeUninit::uninit(); 8];

    // Safe call composes into a ValueRef claiming these 8 uninit bytes are a valid u64.
    let vref = ValueRef::from_raw_parts(&uninit_bytes, TypeId::of::<u64>());

    // Safe call reads uninitialized memory as an initialized u64 -> UB.
    let value: u64 = vref.get::<u64>();
    println!("{}", value);
}

