pub struct ArxivId {
    year: u16,
    month: u8,
    number: String,
    version: Option<u8>,
}

// Fixed lookup table indexed by (month - 1); relies on the invariant
// that `month` is in 1..=12, which is only checked by the safe
// constructor `new`, not by `new_unchecked`.
static MONTH_NAMES: [&str; 12] = [
    "Jan", "Feb", "Mar", "Apr", "May", "Jun",
    "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
];

impl ArxivId {
    /// Safe constructor: validates the precondition.
    pub fn new(year: u16, month: u8, number: String, version: Option<u8>) -> Option<Self> {
        if !(1..=12).contains(&month) {
            return None;
        }
        Some(unsafe { Self::new_unchecked(year, month, number, version) })
    }

    /// Mirrors the real `arxiv` crate's `ArxivIdentifier::new_unchecked`:
    /// marked `unsafe` but performs no validation of `month` before it is
    /// later trusted as a valid 1..=12 discriminant elsewhere in the API.
    pub const unsafe fn new_unchecked(
        year: u16,
        month: u8,
        number: String,
        version: Option<u8>,
    ) -> Self {
        Self {
            year,
            month,
            number,
            version,
        }
    }

    pub fn year(&self) -> u16 {
        self.year
    }

    pub fn version(&self) -> Option<u8> {
        self.version
    }

    pub fn number(&self) -> &str {
        &self.number
    }

    /// Safe-looking accessor that trusts the `month` invariant established
    /// (or not) by construction, using unchecked indexing for performance.
    pub fn month_name(&self) -> &'static str {
        // SAFETY (assumed, not verified): month is in 1..=12 as guaranteed
        // by the constructor contract.
        unsafe { MONTH_NAMES.get_unchecked((self.month - 1) as usize) }
    }
}

/// Public safe wrapper some downstream code might expose around the
/// unsafe constructor without re-deriving the validation itself -
/// this is the composition point a safe caller can (mis)use.
pub fn make_from_untrusted(year: u16, month: u8, number: String, version: Option<u8>) -> ArxivId {
    unsafe { ArxivId::new_unchecked(year, month, number, version) }
}

