// Minimal reconstruction of arrcat's pattern: a type whose only valid
// bit-patterns are a small fixed set, constructed via an `unsafe fn`
// that performs no runtime validation of the discriminant it writes.
#[repr(u8)]
#[derive(Clone, Copy)]
pub enum Tag {
    A = 0,
    B = 1,
}

#[repr(transparent)]
pub struct Wrapper(u8);

impl Wrapper {
    // Mirrors `Self::__NEW`: a fixed "safe-looking" bit pattern baked in
    // at compile time, exposed as a const associated value.
    pub const __NEW: Wrapper = Wrapper(0);

    // Same shape as arrcat's target function: `pub const unsafe fn
    // new_unchecked() -> Self { Self::__NEW }`. It performs no check that
    // the caller-supplied byte (threaded in below) is a legal Tag
    // discriminant before it gets reinterpreted as one.
    pub const unsafe fn new_unchecked(value: u8) -> Self {
        Wrapper(value)
    }

    // Safe public API built on top, exactly like arrcat's safe wrappers
    // that assume the internal representation is always valid.
    pub fn as_tag(&self) -> Tag {
        unsafe { std::mem::transmute::<u8, Tag>(self.0) }
    }
}

// Safe constructor a downstream user might expose, forwarding an
// out-of-range value into the unsafe constructor without validating it
// first -- this is the missing precondition check.
pub fn make_from_safe_input(value: u8) -> Wrapper {
    unsafe { Wrapper::new_unchecked(value) }
}

poc_main_rs:
fn main() {
    // Purely safe Rust: pick a value outside the valid Tag discriminant
    // range {0, 1} and hand it to the safe wrapper API.
    let w = poc_lib::make_from_safe_input(42);

    // Safe code reading the value as an enum with an invalid
    // discriminant is immediate UB.
    match w.as_tag() {
        poc_lib::Tag::A => println!("A"),
        poc_lib::Tag::B => println!("B"),
    }
}

