pub unsafe fn from_raw_parts<'a, T, O>(
	data: BitPtr<Const, T, O>,
	len: usize,
) -> Result<&'a BitSlice<T, O>, BitSpanError<T>>
where
	O: BitOrder,
	T: 'a + BitStore,
{
	data.span(len).map(|bp| bp.into_bitslice_ref())
}

poc_lib_rs:
use std::marker::PhantomData;

pub trait BitOrder: 'static {}
pub struct Lsb0;
impl BitOrder for Lsb0 {}

pub trait BitStore: Sized {}
impl BitStore for u8 {}

#[derive(Clone, Copy)]
pub struct BitPtr<T, O> {
    ptr: *const T,
    _order: PhantomData<O>,
}

impl<T: BitStore, O: BitOrder> BitPtr<T, O> {
    pub fn new(ptr: *const T) -> Self {
        Self { ptr, _order: PhantomData }
    }

    /// Mirrors bitvec's `BitPtr::span`: packs `(ptr, len)` into a span
    /// descriptor. It only validates internal encoding limits (that `len`
    /// doesn't overflow the packed representation) — it has no way to know,
    /// and never checks, whether `len` bits actually fit within whatever
    /// allocation `ptr` points to.
    pub fn span(self, len: usize) -> Result<BitSpan<T, O>, BitSpanError<T>> {
        if len > (isize::MAX as usize) {
            return Err(BitSpanError(PhantomData));
        }
        Ok(BitSpan { ptr: self.ptr, len, _order: PhantomData })
    }
}

pub struct BitSpan<T, O> {
    ptr: *const T,
    len: usize,
    _order: PhantomData<O>,
}

impl<T: BitStore, O: BitOrder> BitSpan<T, O> {
    pub fn into_bitslice_ref<'a>(self) -> &'a BitSlice<T, O> {
        Box::leak(Box::new(BitSlice { ptr: self.ptr, len: self.len, _order: PhantomData }))
    }
}

#[derive(Debug)]
pub struct BitSpanError<T>(PhantomData<T>);

pub struct BitSlice<T, O> {
    ptr: *const T,
    len: usize,
    _order: PhantomData<O>,
}

impl<T: BitStore, O: BitOrder> BitSlice<T, O> {
    pub fn len(&self) -> usize {
        self.len
    }

    pub fn get_bit(&self, index: usize) -> bool {
        let byte_index = index / 8;
        let bit_offset = index % 8;
        unsafe {
            let byte_ptr = (self.ptr as *const u8).add(byte_index);
            let byte = *byte_ptr;
            (byte >> bit_offset) & 1 == 1
        }
    }
}

/// Same signature & body as `bitvec::ptr::from_raw_parts`.
pub unsafe fn from_raw_parts<'a, T, O>(
    data: BitPtr<T, O>,
    len: usize,
) -> Result<&'a BitSlice<T, O>, BitSpanError<T>>
where
    O: BitOrder,
    T: 'a + BitStore,
{
    data.span(len).map(|bp| bp.into_bitslice_ref())
}

/// Safe, modular wrapper around the unsafe primitive — like bitvec's public
/// safe constructors, it forwards a caller-supplied bit length straight into
/// `from_raw_parts` without ever checking it against the real size of `data`.
pub struct Bits {
    data: Vec<u8>,
}

impl Bits {
    pub fn new(data: Vec<u8>) -> Self {
        Self { data }
    }

    pub fn as_bits_with_len(&self, len_bits: usize) -> &BitSlice<u8, Lsb0> {
        let ptr = BitPtr::new(self.data.as_ptr());
        unsafe { from_raw_parts(ptr, len_bits).unwrap() }
    }
}

