use poc_lib::Bits;

fn main() {
    let buf: Vec<u8> = vec![0u8]; // only 1 byte is actually allocated
    let bits = Bits::new(buf);

    // Fully safe call: no `unsafe` keyword appears anywhere in this file.
    let view = bits.as_bits_with_len(64 * 8);

    // Reading bit 500 dereferences far outside the single-byte allocation.
    let _ = view.get_bit(500);
}

