use std::ffi::{CStr, CString};
use std::os::raw::{c_char, c_int, c_void};
use std::panic;
use std::process;

#[derive(Debug, Clone, Copy)]
pub enum MessageType {
    Debug,
    Warning,
}

impl MessageType {
    pub fn from_ffi_type(t: c_int) -> Option<MessageType> {
        match t {
            0 => Some(MessageType::Debug),
            1 => Some(MessageType::Warning),
            _ => None,
        }
    }
}

// Mimics the C library's callback invocation trampoline used internally
// by the real crate's FFI layer.
unsafe extern "system" fn c_callback(msg_type: c_int, msg: *const c_char, user_data: *mut c_void) {
    let closure = panic::AssertUnwindSafe(|| {
        let message_type = MessageType::from_ffi_type(msg_type).unwrap();
        let message = CStr::from_ptr(msg);

        // Is there a better way of casting this?
        let callback = *(&user_data as *const _ as *const fn(MessageType, &CStr));
        (callback)(message_type, message);
    });

    if panic::catch_unwind(closure).is_err() {
        eprintln!("panic in the set_message_handler_trivial() callback, aborting");
        process::abort();
    }
}

/// Safe wrapper mirroring `set_message_handler_trivial`: it accepts any
/// `usize` as the "user data" pointer and simulates the foreign library
/// invoking the registered callback later, without ever validating that
/// `user_data` actually encodes a live function pointer.
pub struct MessageHandler {
    user_data: usize,
}

impl MessageHandler {
    pub fn set_message_handler_trivial(user_data: usize) -> MessageHandler {
        MessageHandler { user_data }
    }

    /// Simulates the C library later calling back into Rust with a
    /// message, exactly as `c_callback` would be invoked from C.
    pub fn fire(&self, msg_type: c_int, msg: &CStr) {
        unsafe {
            c_callback(
                msg_type,
                msg.as_ptr(),
                self.user_data as *mut c_void,
            );
        }
    }
}

pub fn make_message() -> CString {
    CString::new("hello").unwrap()
}

poc_main_rs:
use poc_lib::{make_message, MessageHandler};

fn main() {
    // Purely safe Rust: register a "user_data" value that is not a valid
    // function pointer at all (e.g. an arbitrary integer / dangling value).
    // The safe API happily accepts it because it only stores a usize.
    let bogus_user_data: usize = 0xdead_beef_usize_marker();

    let handler = MessageHandler::set_message_handler_trivial(bogus_user_data);

    let msg = make_message();

    // This triggers the foreign callback trampoline, which reinterprets
    // the bogus usize as `fn(MessageType, &CStr)` and calls through it:
    // an invalid function pointer call (UB), with no `unsafe` in this file.
    handler.fire(0, &msg);
}

fn bogus_user_data_usize_marker() -> usize {
    0xdead_beef
}

