pub(super) unsafe fn new_unchecked<F, S, T>(task: *const Task<F, S, T>) -> Self
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
    S: Fn(Runnable, T) + Send + Sync + 'static,
    T: Clone + Send + Sync + 'static,
{
    Self {
        task: task as *const (),
        vtable: &VTable {
            run: run::<F, S, T>,
            cancel: cancel::<F, S, T>,
        },
    }
}

poc_lib_rs:
use std::future::Future;

pub struct Task<F, S, T> {
    pub future: F,
    pub schedule: S,
    pub value: T,
}

struct VTable {
    run: unsafe fn(*const ()),
    cancel: unsafe fn(*const ()),
}

pub struct Runnable {
    task: *const (),
    vtable: &'static VTable,
}

unsafe fn run<F, S, T>(ptr: *const ())
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
    S: Fn(T) + Send + Sync + 'static,
    T: Clone + Send + Sync + 'static,
{
    let task = ptr as *const Task<F, S, T>;
    // Precondition (never checked): `task` must still point to a live,
    // correctly-typed Task<F,S,T> allocation.
    let value = (*task).value.clone();
    ((*task).schedule)(value);
}

unsafe fn cancel<F, S, T>(_ptr: *const ())
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
    S: Fn(T) + Send + Sync + 'static,
    T: Clone + Send + Sync + 'static,
{
}

impl Runnable {
    // Mirrors asynchronix's `Runnable::new_unchecked`: erases the task's
    // type into an opaque pointer + vtable, trusting the caller that the
    // pointer stays valid and correctly typed for the handle's lifetime.
    pub(crate) unsafe fn new_unchecked<F, S, T>(task: *const Task<F, S, T>) -> Self
    where
        F: Future + Send + 'static,
        F::Output: Send + 'static,
        S: Fn(T) + Send + Sync + 'static,
        T: Clone + Send + Sync + 'static,
    {
        let vtable = Box::leak(Box::new(VTable {
            run: run::<F, S, T>,
            cancel: cancel::<F, S, T>,
        }));
        Self {
            task: task as *const (),
            vtable,
        }
    }

    pub fn run(self) {
        unsafe { (self.vtable.run)(self.task) }
    }
}

// Safe-looking wrapper around the unsafe constructor. Nothing in its
// signature ties the lifetime of the returned `Runnable` to `task`, so the
// missing precondition check on pointer validity leaks straight through to
// fully safe callers.
pub fn make_runnable<F, S, T>(task: &Task<F, S, T>) -> Runnable
where
    F: Future + Send + 'static,
