use std::ptr;

// Minimal reconstruction of hpm5361-pac's generic bitfield-writer machinery
// (RegisterSpec::Ux, FieldWriter::bits) plus the safe modify()/field wrapper
// that the vendor crate exposes on top of it.

pub trait RegisterSpec {
    type Ux: Ux;
}

pub trait Ux: Copy {
    fn mask<const WIDTH: u8>() -> Self;
    fn from_u8(v: u8) -> Self;
}

impl Ux for u32 {
    fn mask<const WIDTH: u8>() -> Self {
        (1u32 << WIDTH) - 1
    }
    fn from_u8(v: u8) -> Self {
        v as u32
    }
}

pub struct MyReg;
impl RegisterSpec for MyReg {
    type Ux = u32;
}

pub struct W<REG: RegisterSpec> {
    pub bits: REG::Ux,
}

pub struct FieldWriter<'a, REG: RegisterSpec, const WIDTH: u8> {
    w: &'a mut W<REG>,
    o: u8,
}

impl<'a, REG: RegisterSpec<Ux = u32>, const WIDTH: u8> FieldWriter<'a, REG, WIDTH> {
    pub fn new(w: &'a mut W<REG>, o: u8) -> Self {
        FieldWriter { w, o }
    }

    // Mirrors hpm5361-pac's generated:
    //   pub unsafe fn bits(self, value: FI::Ux) -> &'a mut W<REG> {
    //       self.w.bits &= !(REG::Ux::mask::<WI>() << self.o);
    //       self.w.bits |= (REG::Ux::from(value) & REG::Ux::mask::<WI>()) << self.o;
    //       self.w
    //   }
    // No check that `value` is a valid encoding for the field -- any raw byte
    // is masked/shifted straight into the register bits.
    pub unsafe fn bits(self, value: u8) -> &'a mut W<REG> {
        self.w.bits &= !(u32::mask::<WIDTH>() << self.o);
        self.w.bits |= (u32::from_u8(value) & u32::mask::<WIDTH>()) << self.o;
        self.w
    }
}

pub struct RegisterBlock {
    // MMIO register address; in this PoC it points at an unmapped device address
    ptr: *mut u32,
}

impl RegisterBlock {
    pub fn new(ptr: *mut u32) -> Self {
        RegisterBlock { ptr }
    }

    // svd2rust-style safe `modify` entry point: builds a `W`, lets the closure
    // touch fields through the (internally-unsafe) FieldWriter, then commits
    // the raw bits straight to the device register.
    pub fn modify<F>(&mut self, f: F)
    where
        F: FnOnce(&mut W<MyReg>) -> &mut W<MyReg>,
    {
        let mut w = W::<MyReg> { bits: 0 };
        f(&mut w);
        unsafe { ptr::write_volatile(self.ptr, w.bits) }
    }

    // Safe convenience wrapper the vendor crate exposes on top of the unsafe
    // `bits()` accessor -- no `unsafe` keyword appears at any call site in
    // user code.
    pub fn set_field(&mut self, value: u8) {
        self.modify(|w| {
            let fw = FieldWriter::<MyReg, 2>::new(w, 30);
            unsafe { fw.bits(value) }
        });
    }
}

