// Self-contained model of the imxrt1062-can1 svd2rust-style register writer.
// `W` is the write-proxy for a 32-bit register; `bits()` is the raw, unchecked
// field setter mirroring the target function's semantics exactly.
use std::ptr;

pub struct W {
    pub bits: u32,
}

pub struct FieldWriter<'a> {
    pub w: &'a mut W,
}

impl<'a> FieldWriter<'a> {
    // mirrors the target: `pub unsafe fn bits(self, value: u8) -> &'a mut W`
    // no check that `value` is a valid encoding for this field before it is
    // folded into the register image and eventually flushed to the device.
    pub unsafe fn bits(self, value: u8) -> &'a mut W {
        self.w.bits = (self.w.bits & !(0xff << 8)) | (((value as u32) & 0xff) << 8);
        self.w
    }
}

pub struct RegisterBlock {
    pub reg: *mut u32,
}

impl RegisterBlock {
    // Safe, high-level setter as exposed by generated PAC crates: no `unsafe`
    // at the call site even though it internally calls the unsafe `bits()`
    // and performs the volatile MMIO write with the unchecked raw value.
    pub fn set_field_raw(&mut self, value: u8) {
        let mut w = W { bits: 0 };
        let w_ref: &mut W = unsafe { FieldWriter { w: &mut w }.bits(value) };
        let final_bits = w_ref.bits;
        // Flush composed register image straight to the mapped device address,
        // exactly as an svd2rust `write` method would.
        unsafe { ptr::write_volatile(self.reg, final_bits) }
    }
}

