use std::ptr;

// Mirrors an svd2rust-generated register writer proxy (`W`) and field writer (`_BITS_W`)
// for the imxrt1062-dcdc DCDC_REG3 TRG field (a 3-bit raw field at bit offset 5).
pub struct W {
    pub bits: u32,
    pub reg_ptr: *mut u32,
}

pub struct BitsW<'a> {
    pub w: &'a mut W,
}

impl<'a> BitsW<'a> {
    // Reconstructed target function: masks to 3 bits, shifts into field position,
    // and stores into the register mirror with no range/encoding validation.
    // (Original crate marks this `unsafe fn`, but downstream register blocks
    // commonly expose a safe wrapping accessor, so callers reach this with no
    // unsafe block of their own.)
    pub fn bits(self, value: u8) -> &'a mut W {
        self.w.bits = (self.w.bits & !(0x07 << 5)) | (((value as u32) & 0x07) << 5);
        self.w
    }
}

impl W {
    pub fn trg(&mut self) -> BitsW<'_> {
        BitsW { w: self }
    }

    // Safe-looking public API (as real PAC register blocks expose): commits
    // the composed bit pattern to the device register via a volatile write.
    // No validation occurs anywhere on this path.
    pub fn commit(&mut self) {
        unsafe { ptr::write_volatile(self.reg_ptr, self.bits) }
    }
}

pub struct Dcdc3Reg {
    pub reg_ptr: *mut u32,
}

impl Dcdc3Reg {
    // Safe wrapper mimicking svd2rust's `modify`/`write` closures: no unsafe
    // needed at the call site even though it ends in a raw MMIO write.
    pub fn write<F>(&mut self, f: F)
    where
        F: FnOnce(&mut W) -> &mut W,
    {
        let mut w = W { bits: 0, reg_ptr: self.reg_ptr };
        f(&mut w);
        w.commit();
    }
}

