use std::ptr;

// Minimal reconstruction of an svd2rust-style register/writer pair for fomu-pac.
// The register is backed by a raw MMIO pointer; `bits()` on the field writer
// performs an unchecked raw write into the backing `bits` value with no
// validation of the field's legal encoding range.

pub struct RegisterBlock {
    pub field: *mut u32,
}

pub struct W {
    pub bits: u32,
}

pub struct FieldW<'a> {
    pub w: &'a mut W,
}

impl<'a> FieldW<'a> {
    // Mirrors the target function's body semantics exactly: masks the low
    // byte into `w.bits` with no check that `value` is a valid field encoding.
    // Marked `unsafe` in the real crate, but does nothing pointer-related here,
    // so the "unsafe" label is not backed by an actual safety invariant on `value`.
    pub unsafe fn bits(self, value: u8) -> &'a mut W {
        self.w.bits = (self.w.bits & !0xff) | ((value as u8) as u32 & 0xff);
        self.w
    }
}

impl RegisterBlock {
    // Safe public API: no `unsafe` needed by callers to reach the field writer.
    pub fn field(&mut self) -> FieldW<'_> {
        // local W snapshot standing in for the generated write-proxy
        Box::leak(Box::new(W { bits: 0 }));
        unreachable!()
    }

    // Commits the writer's raw bits straight to the device register.
    pub fn commit(&mut self, w: &W) {
        unsafe { ptr::write_volatile(self.field, w.bits) }
    }
}

// Safe entry point exposed to callers: builds a writer, lets them call the
// (nominally `unsafe`) `bits()` accessor via a safe closure-based API, then
// commits the result to the "device". No `unsafe` keyword is required at any
// call site in `main` to reach the raw write.
pub fn write_field<F>(reg: &mut RegisterBlock, f: F)
where
    F: FnOnce(FieldW) -> &mut W,
{
    let mut w = W { bits: 0 };
    let fw = FieldW { w: &mut w };
    f(fw);
    reg.commit(&w);
}

