    // module's unchecked raw-bits accessor and writes an out-of-range value
    // straight through to the simulated device register.
    write_field(&mut reg, |fw| {
        // SAFETY note: in the real crate this call requires `unsafe`, but the
        // wrapping API above lets safe code drive it end-to-end without ever
        // writing the `unsafe` keyword itself, since the closure body is the
        // only place bits() is invoked and it is hidden behind a safe helper.
        fw.w.bits = 0xFF; // stand-in for calling bits(0xFF) through the writer
        fw.w
