// Minimal reconstruction of arrow-data's ArrayData / NullBuffer / BooleanBuffer
// and the unsafe `build_impl` that trusts a caller-supplied `null_count`
// without validating it against the actual bitmap contents.

pub struct BooleanBuffer {
    bytes: Vec<u8>,
    offset: usize,
    len: usize,
}

impl BooleanBuffer {
    pub fn new(bytes: Vec<u8>, offset: usize, len: usize) -> Self {
        Self { bytes, offset, len }
    }

    #[inline]
    pub fn value(&self, i: usize) -> bool {
        let idx = self.offset + i;
        (self.bytes[idx / 8] >> (idx % 8)) & 1 != 0
    }

    pub fn len(&self) -> usize {
        self.len
    }
}

pub struct NullBuffer {
    buffer: BooleanBuffer,
    null_count: usize,
}

impl NullBuffer {
    pub fn new(buffer: BooleanBuffer) -> Self {
        let null_count = (0..buffer.len()).filter(|&i| !buffer.value(i)).count();
        Self { buffer, null_count }
    }

    /// # Safety
    /// Caller must guarantee `null_count` equals the number of unset bits in `buffer`.
    /// arrow-data's real implementation trusts this value verbatim (this is the
    /// missing-check root cause: nothing here re-derives or validates it).
    pub unsafe fn new_unchecked(buffer: BooleanBuffer, null_count: usize) -> Self {
        Self { buffer, null_count }
    }

    pub fn null_count(&self) -> usize {
        self.null_count
    }

    pub fn is_valid(&self, i: usize) -> bool {
        self.buffer.value(i)
    }
}

pub struct ArrayData {
    pub len: usize,
    pub buffer: Vec<i32>,
    pub nulls: Option<NullBuffer>,
}

impl ArrayData {
    #[inline]
    pub fn value(&self, i: usize) -> i32 {
        // Safe consumer code trusts null_count()==0 / is_valid() to mean the
        // slot always holds a meaningful, in-range value it can safely index.
        if let Some(nulls) = &self.nulls {
            if nulls.null_count() == 0 || nulls.is_valid(i) {
                return self.buffer[self.buffer_index(i)];
            }
            return 0;
        }
        self.buffer[i]
    }

    #[inline]
    fn buffer_index(&self, i: usize) -> usize {
        // In real arrow-data, a null_count of 0 lets many code paths skip
        // validity checks entirely and index other buffers unchecked based on
        // the (falsely) reported non-null count; we model that trust here by
        // deriving an index that only stays in-bounds when null_count is correct.
        self.buffer.len() - 1 - i
    }
}

pub struct ArrayDataBuilder {
    pub len: usize,
    pub offset: usize,
    pub buffer: Vec<i32>,
    pub null_bit_buffer: Option<Vec<u8>>,
    pub null_count: Option<usize>,
}

impl ArrayDataBuilder {
    pub fn new(len: usize, buffer: Vec<i32>) -> Self {
        Self { len, offset: 0, buffer, null_bit_buffer: None, null_count: None }
    }

    pub fn null_bit_buffer(mut self, bytes: Vec<u8>) -> Self {
        self.null_bit_buffer = Some(bytes);
        self
    }

    // Public safe setter: nothing here validates that `n` actually matches
    // the bitmap passed to `null_bit_buffer` -- this is the missing precondition check.
    pub fn null_count(mut self, n: usize) -> Self {
        self.null_count = Some(n);
        self
    }

    /// Public safe entry point (mirrors arrow-data's `ArrayDataBuilder::build`),
    /// which internally calls the unsafe `build_impl` without re-validating
    /// that `null_count` matches the bitmap.
    pub fn build(self) -> ArrayData {
        unsafe { self.build_impl() }
    }

    unsafe fn build_impl(self) -> ArrayData {
        let nulls = self.null_bit_buffer.map(|bytes| {
            let buffer = BooleanBuffer::new(bytes, self.offset, self.len);
            match self.null_count {
                Some(n) => NullBuffer::new_unchecked(buffer, n),
                None => NullBuffer::new(buffer),
            }
        });

        ArrayData { len: self.len, buffer: self.buffer, nulls }
    }
}

