use poc_lib::ArrayDataBuilder;

fn main() {
    // All bits set => bitmap says "zero nulls", but we lie and claim null_count = 5.
    let all_valid_bitmap = vec![0xFFu8];

    let data = ArrayDataBuilder::new(5, vec![10, 20, 30])
        .null_bit_buffer(all_valid_bitmap)
        .null_count(5) // caller-supplied count is never checked against the bitmap
        .build(); // safe call site, no `unsafe` keyword needed

    // Consumer trusts the bogus null_count()==0 branch never gets hit / is_valid path,
    // deriving an index that goes out of bounds on the underlying Vec.
    let v = data.value(4);
    println!("{}", v);
}

