use std::ops::Deref;

// Minimal stand-in for bcder's `Bytes` (backed by a Vec<u8>).
#[derive(Clone)]
pub struct Bytes(Vec<u8>);

impl Bytes {
    pub fn from_static(b: &'static [u8]) -> Self {
        Bytes(b.to_vec())
    }
}

impl Deref for Bytes {
    type Target = [u8];
    fn deref(&self) -> &[u8] {
        &self.0
    }
}

// Minimal stand-in for bcder's `Integer` type.
pub struct Integer(Bytes);

impl Integer {
    // SAFETY (as documented upstream, but NOT enforced here): `bytes` must be
    // a non-empty, minimal-length two's-complement BER INTEGER encoding.
    // The function itself performs no validation of this precondition.
    unsafe fn from_bytes_unchecked(bytes: Bytes) -> Self {
        Integer(bytes)
    }

    // Safe public wrapper, mirroring how bcder's parsing/constructors funnel
    // externally-controlled byte slices into `from_bytes_unchecked` without
    // checking length or content first.
    pub fn from_bytes_safe(bytes: Bytes) -> Self {
        unsafe { Self::from_bytes_unchecked(bytes) }
    }

    // Mirrors real Integer usage: code that trusts the "at least one byte,
    // sign in the first byte" invariant that `from_bytes_unchecked` was
    // supposed to guarantee but never checked.
    pub fn is_negative(&self) -> bool {
        // Out-of-bounds read / UB when self.0 is empty: get_unchecked skips
        // the bounds check that safe indexing would normally perform.
        unsafe { *self.0.get_unchecked(0) & 0x80 != 0 }
    }
}

