use std::marker::PhantomData;

struct Inner<T> {
    buf: *const T,
    nrows: usize,
    ncols: usize,
    rs: isize,
    cs: isize,
}

pub struct Mat<T> {
    inner: Inner<T>,
    _marker: PhantomData<T>,
}

impl<T> Mat<T> {
    pub unsafe fn from_raw_parts(
        buf: *const T,
        nrows: usize,
        ncols: usize,
        row_stride: isize,
        col_stride: isize,
    ) -> Self {
        Self {
            inner: Inner {
                buf,
                nrows,
                ncols,
                rs: row_stride,
                cs: col_stride,
            },
            _marker: PhantomData,
        }
    }

    // Safe constructor: takes ownership of a Vec and derives a raw pointer
    // from it, but never validates that `nrows`/`ncols`/strides actually fit
    // within `data`'s length before handing everything to from_raw_parts.
    pub fn from_vec(data: Vec<T>, nrows: usize, ncols: usize, row_stride: isize, col_stride: isize) -> Self {
        let buf = data.as_ptr();
        std::mem::forget(data);
        unsafe { Self::from_raw_parts(buf, nrows, ncols, row_stride, col_stride) }
    }

    pub fn get(&self, i: usize, j: usize) -> T
    where
        T: Copy,
    {
        // Trusts self.inner.rs/cs/nrows/ncols to be consistent with the
        // real buffer size, which from_vec never guaranteed.
        let offset = self.inner.rs * i as isize + self.inner.cs * j as isize;
        unsafe { *self.inner.buf.offset(offset) }
    }
}

