use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicBool, Ordering};

pub struct SpinBase<T> {
    lock: AtomicBool,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for SpinBase<T> {}

impl<T> SpinBase<T> {
    pub const fn new(data: T) -> Self {
        Self { lock: AtomicBool::new(false), data: UnsafeCell::new(data) }
    }

    pub fn lock(&self) -> Guard<'_, T> {
        while self
            .lock
            .compare_exchange_weak(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            std::hint::spin_loop();
        }
        Guard { base: self }
    }

    /// # Safety
    /// Caller must ensure no `Guard` is currently alive when calling this,
    /// otherwise the lock invariant (at most one live guard) is violated.
    pub unsafe fn force_unlock(&self) {
        #[cfg(feature = "smp")]
        self.lock.store(false, Ordering::Release);
    }

    // A "convenience" safe wrapper the crate ships for callers who lost
    // their guard (e.g. via mem::forget) and need to manually release the
    // lock. It requires no `unsafe` at the call site.
    pub fn unlock_unchecked(&self) {
        unsafe { self.force_unlock() }
    }
}

pub struct Guard<'a, T> {
    base: &'a SpinBase<T>,
}

impl<'a, T> std::ops::Deref for Guard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.base.data.get() }
    }
}

impl<'a, T> std::ops::DerefMut for Guard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.base.data.get() }
    }
}

impl<'a, T> Drop for Guard<'a, T> {
    fn drop(&mut self) {
        self.base.lock.store(false, Ordering::Release);
    }
}

