use poc_lib::SpinBase;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let base = Arc::new(SpinBase::new(0i32));
    let b2 = Arc::clone(&base);

    let h = thread::spawn(move || {
        let mut guard = b2.lock();
        thread::sleep(Duration::from_millis(200));
        *guard += 1; // this thread believes it has exclusive access
        thread::sleep(Duration::from_millis(200));
    });

    thread::sleep(Duration::from_millis(100));

    // Purely safe call: forces the spinlock flag back to "unlocked"
    // while the guard created above is still alive on another thread.
    base.unlock_unchecked();

    // Safe code can now acquire a second, concurrent guard on the same data.
    let mut guard2 = base.lock();
    *guard2 += 100; // unsynchronized concurrent write -> data race

    h.join().unwrap();
    println!("{}", *guard2);
}

