use std::cell::UnsafeCell;
use std::ops::{Deref, DerefMut};
use std::sync::atomic::{AtomicBool, Ordering};

pub struct Lock<T> {
    locked: AtomicBool,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for Lock<T> {}

pub struct Guard<'a, T> {
    lock: &'a Lock<T>,
}

impl<T> Lock<T> {
    pub fn new(data: T) -> Self {
        Self {
            locked: AtomicBool::new(false),
            data: UnsafeCell::new(data),
        }
    }

    pub fn try_lock(&self) -> Option<Guard<T>> {
        if self
            .locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Acquire)
            .is_ok()
        {
            Some(Guard { lock: self })
        } else {
            None
        }
    }

    pub fn lock(&self) -> Guard<T> {
        loop {
            if let Some(g) = self.try_lock() {
                return g;
            }
            std::thread::yield_now();
        }
    }

    // Target function: caller must uphold that no Guard is currently live.
    // emerald_std ships this as `unsafe fn` for exactly that reason.
    pub unsafe fn unlock(&self) {
        self.locked.store(false, Ordering::Release);
    }

    // Safe modular wrapper shipped alongside it: it swallows the invariant
    // check entirely and lets any safe caller flip `locked` back to false
    // regardless of whether a Guard is outstanding.
    pub fn force_unlock(&self) {
        unsafe { self.unlock() }
    }
}

impl<'a, T> Deref for Guard<'a, T> {
    type Target = T;
    fn deref(&self) -> &T {
        unsafe { &*self.lock.data.get() }
    }
}

impl<'a, T> DerefMut for Guard<'a, T> {
    fn deref_mut(&mut self) -> &mut T {
        unsafe { &mut *self.lock.data.get() }
    }
}

