use std::sync::Arc;
use std::thread;
use std::time::Duration;

fn main() {
    let lock = Arc::new(Lock::new(0i32));
    let lock2 = lock.clone();

    let h = thread::spawn(move || {
        let mut guard = lock2.lock();
        for i in 0..5_000_000 {
            *guard = i;
        }
        thread::sleep(Duration::from_millis(200));
    });

    thread::sleep(Duration::from_millis(50));

    // No `unsafe` here: force_unlock is a totally safe call site.
    lock.force_unlock();

    let mut guard2 = lock.lock();
    for i in 0..5_000_000 {
        *guard2 = i + 1;
    }

    h.join().unwrap();
