use std::os::raw::c_char;
use std::slice;
use std::str;

#[repr(C)]
pub struct TSHighlighter {
    pub name: String,
}

#[repr(C)]
#[derive(Debug, PartialEq)]
pub enum ErrorCode {
    Ok,
    InvalidUtf8,
}

unsafe fn unwrap_mut_ptr<'a, T>(ptr: *mut T) -> &'a mut T {
    &mut *ptr
}

/// # Safety
/// `this` must be a valid pointer to a live `TSHighlighter`, and `query`
/// must point to at least `query_len` valid, initialized bytes.
/// Mirrors tree-sitter-highlight's `ts_highlighter_add_language`: it takes
/// a raw pointer plus an independently supplied length and never validates
/// that the length matches the real allocation behind `query`.
pub unsafe extern "C" fn ts_highlighter_add_language(
    this: *mut TSHighlighter,
    query: *const c_char,
    query_len: u32,
) -> ErrorCode {
    let f = move || {
        let this = unwrap_mut_ptr(this);

        // Same root cause as upstream: trusts caller-provided length,
        // no check against the actual buffer size behind `query`.
        let bytes = slice::from_raw_parts(query.cast::<u8>(), query_len as usize);
        let s = str::from_utf8(bytes).or(Err(ErrorCode::InvalidUtf8))?;

        this.name = s.to_string();
        Ok(())
    };

    match f() {
        Ok(()) => ErrorCode::Ok,
        Err(e) => e,
    }
}

/// Safe-looking public wrapper, analogous to the crate's safe C-API layer:
/// callers pass a plain `&str` plus a length, and the wrapper forwards both
/// straight into the FFI call with no validation that they agree.
pub fn add_language_safe(this: &mut TSHighlighter, query: &str, query_len: u32) -> ErrorCode {
    unsafe {
        ts_highlighter_add_language(
            this as *mut TSHighlighter,
            query.as_ptr().cast::<c_char>(),
            query_len,
        )
    }
}

poc_main_rs:
use poc_lib::{add_language_safe, TSHighlighter};

fn main() {
    let mut highlighter = TSHighlighter {
        name: String::new(),
    };

    // A tiny, perfectly valid 2-byte string...
    let query = "ab";

    // ...but we (safely!) claim it is 1000 bytes long. Nothing in the
    // public API stops this: `add_language_safe` and the FFI function it
    // wraps never check `query_len` against `query.len()`.
    let code = add_language_safe(&mut highlighter, query, 1000);

    println!("result: {:?}, name: {}", code, highlighter.name);
}

