use std::marker::PhantomData;
use std::ptr;

// Minimal svd2rust-style register model for the ENET field write path.
pub struct RegisterBlock {
    pub field: *mut u32,
}

pub struct W<'a> {
    pub bits: u32,
    _marker: PhantomData<&'a mut RegisterBlock>,
}

pub struct FieldWriter<'a> {
    w: &'a mut W<'a>,
}

impl<'a> W<'a> {
    pub fn new() -> Self {
        W { bits: 0, _marker: PhantomData }
    }

    // Safe wrapper mimicking svd2rust's generated `.field()` proxy accessor.
    pub fn field(&mut self) -> FieldWriter<'_> {
        FieldWriter { w: unsafe { std::mem::transmute::<&mut W<'a>, &'a mut W<'a>>(self) } }
    }
}

impl<'a> FieldWriter<'a> {
    // Mirrors the real target: marked `unsafe` in the type signature but
    // performs no validation of `value` against the field's valid encoding.
    pub unsafe fn bits(self, value: u8) -> &'a mut W<'a> {
        self.w.bits = (self.w.bits & !(0x7f << 8)) | (((value as u32) & 0x7f) << 8);
        self.w
    }
}

impl RegisterBlock {
    // Safe public API: internally calls the `unsafe fn bits` for the caller,
    // so no `unsafe` keyword is required at the call site in user code.
    pub fn set_ctrl_raw(&mut self, value: u8) {
        let mut w = W::new();
        // SAFETY (module author's, not checked): value is assumed to be a
        // valid encoding for the field -- never enforced.
        let w = unsafe { w.field().bits(value) };
        unsafe { ptr::write_volatile(self.field, w.bits) }
    }
}

