use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicUsize, Ordering};

const READER: usize = 1 << 2;
const WRITER: usize = 1;

/// Minimal reconstruction of spinny's RawSpinlock reader/writer state machine.
pub struct RawSpinlock {
    lock: AtomicUsize,
}

impl RawSpinlock {
    pub const fn new() -> Self {
        Self { lock: AtomicUsize::new(0) }
    }

    fn ulock(&self) -> &AtomicUsize {
        &self.lock
    }

    pub fn try_lock_shared(&self) -> bool {
        let value = self.ulock().fetch_add(READER, Ordering::Acquire);
        if value & WRITER != 0 {
            self.ulock().fetch_sub(READER, Ordering::Release);
            false
        } else {
            true
        }
    }

    pub fn try_lock_exclusive(&self) -> bool {
        self.ulock()
            .compare_exchange(0, WRITER, Ordering::Acquire, Ordering::Relaxed)
            .is_ok()
    }

    // SAFETY (per spinny): caller must currently hold a shared lock it
    // previously acquired via `try_lock_shared`. Nothing in the type
    // system enforces this -- it's a bare unsafe fn with a documented
    // precondition, matching spinny's `unlock_shared`.
    unsafe fn unlock_shared(&self) {
        self.ulock().fetch_sub(READER, Ordering::Release);
    }

    // A safe public wrapper that never checks the precondition above.
    // This is the modular-unsafe defect: safe code can call it at any
    // time, regardless of whether it actually owns a shared lock.
    pub fn force_unlock_shared(&self) {
        unsafe { self.unlock_shared() }
    }
}

pub struct RwLock<T> {
    raw: RawSpinlock,
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Sync for RwLock<T> {}
unsafe impl<T: Send> Send for RwLock<T> {}

impl<T> RwLock<T> {
    pub fn new(t: T) -> Self {
        Self { raw: RawSpinlock::new(), data: UnsafeCell::new(t) }
    }

    pub fn read(&self) -> Option<&T> {
        if self.raw.try_lock_shared() {
            Some(unsafe { &*self.data.get() })
        } else {
            None
        }
    }

    pub fn write(&self) -> Option<&mut T> {
        if self.raw.try_lock_exclusive() {
            Some(unsafe { &mut *self.data.get() })
        } else {
            None
        }
    }

    // Safe, public: forcibly drops the shared-reader refcount by one,
    // without requiring proof that a read guard is actually being given up.
    pub fn force_unlock_read(&self) {
        self.raw.force_unlock_shared();
    }
}

poc_main_rs:
use poc::RwLock;
use std::sync::Arc;
use std::thread;

fn main() {
    let lock = Arc::new(RwLock::new(0i32));

    // Acquire a shared ("read") lock and keep the borrow alive.
    let reader = lock.read().unwrap();

    // Misuse, entirely in safe code: force-release the shared lock's
    // refcount without actually giving up the `reader` borrow above.
    // This mirrors calling the module's unsafe `unlock_shared` outside
    // of its documented precondition.
    lock.force_unlock_read();

    // The lock now looks unheld, so a writer can acquire it concurrently
    // with the still-alive `reader` reference on the main thread.
    let l2 = Arc::clone(&lock);
    let writer_thread = thread::spawn(move || {
        if let Some(w) = l2.write() {
            for i in 0..1_000_000i32 {
                *w = i; // unsynchronized write
            }
        }
    });

    let mut last = *reader;
    for _ in 0..1_000_000 {
        let cur = *reader; // unsynchronized read, races with the writer thread
        if cur != last {
            println!("data race observed: {} -> {}", last, cur);
        }
        last = cur;
    }

    writer_thread.join().unwrap();
}

