use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicUsize, Ordering};

// Minimal reconstruction of cowstr's shared-buffer refcount/len primitive.
// `len` doubles as a shared "how much of `data` is valid/owned" counter.
pub struct SharedBuf {
    len: AtomicUsize,
    data: UnsafeCell<[u8; 8]>,
}

unsafe impl Sync for SharedBuf {}

impl SharedBuf {
    pub fn new(n: usize) -> Self {
        SharedBuf {
            len: AtomicUsize::new(n),
            data: UnsafeCell::new([0u8; 8]),
        }
    }

    // Faithful to target: internal, marked `unsafe fn`, but nothing prevents
    // a safe wrapper from calling it without synchronizing with readers.
    unsafe fn len_sub_release(&self, n: usize) {
        self.len.fetch_sub(n, Ordering::Release);
    }

    // Safe public wrapper: this is the "modular unsafe function" surface —
    // callable from safe Rust, internally invokes the unsafe primitive.
    pub fn shrink(&self, n: usize) {
        unsafe { self.len_sub_release(n) };
    }

    // Safe public reader that touches the same memory location `shrink`
    // is implicitly meant to guard, using only Acquire on the counter.
    pub fn write_byte(&self, idx: usize, val: u8) {
        // Acquire here pairs with the Release above, but Release/Acquire on a
        // counter alone does not stop the racing write below from being
        // truly concurrent with `shrink`'s own bookkeeping.
        let _ = self.len.load(Ordering::Acquire);
        unsafe {
            (*self.data.get())[idx] = val;
        }
    }
}

