    let s1 = shared.clone();
    let s2 = shared.clone();

    let h1 = thread::spawn(move || {
        for _ in 0..1000 {
            s1.shrink(1);
        }
    });

    let h2 = thread::spawn(move || {
        for i in 0..1000 {
            s2.write_byte(i % 8, i as u8);
        }
    });

    h1.join().unwrap();
    h2.join().unwrap();
}

