use std::cell::UnsafeCell;
use std::mem::MaybeUninit;

const CAP: usize = 4;

pub struct Aovec<T> {
    data: UnsafeCell<[MaybeUninit<T>; CAP]>,
    len: UnsafeCell<usize>,
}

impl<T> Aovec<T> {
    pub fn new() -> Self {
        Aovec {
            data: UnsafeCell::new(unsafe { MaybeUninit::uninit().assume_init() }),
            len: UnsafeCell::new(0),
        }
    }

    pub fn push(&self, value: T) {
        unsafe {
            let len = *self.len.get();
            (*self.data.get())[len] = MaybeUninit::new(value);
            *self.len.get() = len + 1;
        }
    }

    pub fn len(&self) -> usize {
        unsafe { *self.len.get() }
    }

    // Mirrors aovec's `pub unsafe fn get_unchecked(&self, idx: usize) -> &T { self._get(idx) }`
    pub unsafe fn get_unchecked(&self, idx: usize) -> &T {
        self._get(idx)
    }

    unsafe fn _get(&self, idx: usize) -> &T {
        (*self.data.get())[idx].assume_init_ref()
    }

    // Safe public API: only checks capacity, not how many elements were
    // actually pushed (len), before delegating to the unsafe getter.
    pub fn get(&self, idx: usize) -> &T {
        assert!(idx < CAP, "index out of capacity");
        unsafe { self.get_unchecked(idx) }
    }
}

