poc_lib_rs:
use std::cell::UnsafeCell;
use std::mem::MaybeUninit;

pub const SIZE: usize = 8;

pub struct Buf {
    data: UnsafeCell<[MaybeUninit<u8>; SIZE]>,
    len: usize,
}

impl Buf {
    pub fn new() -> Self {
        Buf {
            data: UnsafeCell::new([MaybeUninit::<u8>::uninit(); SIZE]),
            len: 0,
        }
    }

    // Safe API: fill the buffer with real bytes and record how much is initialized.
    pub fn fill(&mut self) {
        let ptr = self.data.get() as *mut u8;
        for i in 0..SIZE {
            unsafe { *ptr.add(i) = 0xABu8; }
        }
        self.len = SIZE;
    }

    // Target function: swaps the backing storage for fresh uninitialized memory.
    // Kept `unsafe` per the module's original signature, but only reachable
    // through the safe wrapper below, which forgets to reset `len`.
    unsafe fn move_data_uninit(&mut self) -> UnsafeCell<[MaybeUninit<u8>; SIZE]> {
        let fill = UnsafeCell::new([MaybeUninit::<u8>::uninit(); SIZE]);
        std::mem::replace(&mut self.data, fill)
    }

    // Safe wrapper: internally calls the unsafe primitive but never touches `len`,
    // silently breaking the "len bytes of data are initialized" invariant.
    pub fn reset_storage(&mut self) {
        let _old = unsafe { self.move_data_uninit() };
        // `len` is intentionally left as-is, matching a plausible real bug
        // where the author forgot len = 0 here.
    }

    // Safe accessor that trusts `len` to describe how much of `data` is initialized.
    pub fn get_initialized(&self) -> &[u8] {
        let ptr = self.data.get() as *const u8;
        unsafe { std::slice::from_raw_parts(ptr, self.len) }
    }
}

