pub struct ScalarBuffer<O>(pub Vec<O>);

pub struct OffsetBuffer<O>(ScalarBuffer<O>);

impl OffsetBuffer<i32> {
    // Precondition (NOT checked here): `buffer` must be non-empty, monotonically
    // non-decreasing, and every entry must be a valid in-bounds index into the
    // values buffer this OffsetBuffer will be paired with.
    pub unsafe fn new_unchecked(buffer: ScalarBuffer<i32>) -> Self {
        Self(buffer)
    }

    pub fn offsets(&self) -> &[i32] {
        &self.0 .0
    }
}

// Safe on the surface, but forwards caller-controlled data straight into the
// unsafe constructor without validating the invariant. This is the missing
// precondition check: any safe caller can now build an out-of-bounds OffsetBuffer.
impl From<Vec<i32>> for OffsetBuffer<i32> {
    fn from(v: Vec<i32>) -> Self {
        unsafe { OffsetBuffer::new_unchecked(ScalarBuffer(v)) }
    }
}

pub struct StringArray {
    values: Vec<u8>,
    offsets: OffsetBuffer<i32>,
}

impl StringArray {
    pub fn new(values: Vec<u8>, offsets: OffsetBuffer<i32>) -> Self {
        Self { values, offsets }
    }

    // Trusts the OffsetBuffer invariant (in-bounds, monotonic offsets) that
    // `new_unchecked` was supposed to guarantee, so it skips bounds checks
    // for performance, exactly like arrow-rs's real value accessors do.
    pub fn value(&self, i: usize) -> &str {
        let offs = self.offsets.offsets();
        let start = offs[i] as usize;
        let end = offs[i + 1] as usize;
        unsafe {
            let slice = self.values.get_unchecked(start..end);
            std::str::from_utf8_unchecked(slice)
        }
    }
}

