    let values = b"hi".to_vec();

    // Fully safe: `From<Vec<i32>>` never validates monotonicity or bounds,
    // so we can hand it offsets that point far past the end of `values`.
    let offsets: OffsetBuffer<i32> = vec![0, 1000, 2000].into();

    let arr = StringArray::new(values, offsets);

    // Reads bytes [1000..2000) of a 2-byte Vec via get_unchecked -> out-of-bounds
    // access, all from safe code.
    println!("{}", arr.value(0));
}

