use std::ptr;

// Minimal reconstruction of an svd2rust-style register writer/proxy,
// mirroring bxcan's `fn bits(self, value: u8) -> &'a mut W` field-write pattern.
pub struct W {
    pub bits: u32,
}

pub struct RegisterBlock {
    pub reg: *mut u32,
}

pub struct FieldWriter<'a> {
    pub w: &'a mut W,
}

impl<'a> FieldWriter<'a> {
    // Same semantics as the target: mask into a 3-bit field at offset 20,
    // no validation that `value` is one of the field's defined encodings.
    pub fn bits(self, value: u8) -> &'a mut W {
        self.w.bits = (self.w.bits & !(0x07 << 20)) | (((value as u32) & 0x07) << 20);
        self.w
    }
}

impl W {
    pub fn field(&mut self) -> FieldWriter<'_> {
        FieldWriter { w: self }
    }
}

impl RegisterBlock {
    // Commits the shadow value to the device register via a raw volatile write,
    // exactly as svd2rust-generated `write()` methods do internally.
    pub fn write<F>(&mut self, f: F)
    where
        F: FnOnce(&mut W) -> &mut W,
    {
        let mut w = W { bits: 0 };
        f(&mut w);
        unsafe { ptr::write_volatile(self.reg, w.bits) }
    }
}

