use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;

/// Minimal stand-in for blaze-rs's RawCommandQueue: just something
/// the supplier closure can be called with.
pub struct RawCommandQueue;

/// Minimal stand-in for blaze-rs's RawEvent: represents a completion
/// notification that can register a completion callback, mimicking
/// the driver-thread-invoked completion mechanism in blaze-rs.
pub struct RawEvent {
    on_complete: std::sync::Mutex<Option<Box<dyn FnOnce() + Send>>>,
}

impl RawEvent {
    pub fn new() -> Self {
        RawEvent { on_complete: std::sync::Mutex::new(None) }
    }

    /// Registers a completion callback. In real blaze-rs this callback
    /// is invoked asynchronously by an OpenCL driver thread when the
    /// GPU event completes -- here we spawn a thread to model that
    /// same asynchronous, unsynchronized-with-caller invocation.
    fn set_on_complete<F: FnOnce() + Send + 'static>(&self, f: F) {
        *self.on_complete.lock().unwrap() = Some(Box::new(f));
    }

    /// Simulates the driver firing the completion callback on its own
    /// thread, independent of whatever the enqueuing thread is doing.
    pub fn fire_completion_async(self: Arc<Self>) {
        std::thread::spawn(move || {
            if let Some(f) = self.on_complete.lock().unwrap().take() {
                f();
            }
        });
    }
}

pub trait Consumer: Send + 'static {
    /// Gives raw (unsynchronized) mutable access to the buffer the
    /// event is supposed to be guarding, just like a real Consumer
    /// would hand back a mapped buffer pointer once the op completes.
    fn buffer(&self) -> Arc<AtomicPayload>;
}

/// The "shared data" the event's completion is supposed to protect.
/// A plain (non-atomic) u64 written through raw pointer casts to
/// model a real GPU-mapped buffer with no built-in synchronization.
pub struct AtomicPayload(pub std::cell::UnsafeCell<u64>);
unsafe impl Sync for AtomicPayload {}

pub struct Event<C: Consumer> {
    pub raw: Arc<RawEvent>,
    pub consumer: C,
}

impl<C: Consumer> Event<C> {
    pub fn new(inner: RawEvent, consumer: C) -> Self {
        Event { raw: Arc::new(inner), consumer }
    }

    pub fn on_complete_silent<F: FnOnce(&Self, &C) + Send + 'static>(&self, f: F) -> Result<(), ()>
    where C: Clone {
        // Real blaze-rs registers this closure to run on the driver's
        // completion thread with NO synchronization barrier back to
        // the thread that called enqueue_unchecked -- only an atomic
        // refcount (`size`) is updated, the guarded payload itself is not.
        let raw = self.raw.clone();
        let consumer = self.consumer.clone();
        // capture self by constructing a lightweight proxy since RawEvent
        // doesn't need Self here for the PoC's purposes
        struct Proxy<C: Consumer> { raw: Arc<RawEvent>, consumer: C }
        let _ = &raw; // raw kept alive
        raw.set_on_complete(move || {
            // This runs asynchronously on a separate OS thread with no
            // lock/fence pairing against the enqueuing thread.
            let _ = &consumer;
            f_call(f, &consumer);
        });
        Ok(())
    }
}

fn f_call<C, F: FnOnce(&(), &C)>(f: F, c: &C) {
    f(&(), c);
}

pub type Result<T> = std::result::Result<T, ()>;

/// Faithful reconstruction of blaze-rs's Queue::enqueue_unchecked.
/// It keeps an atomic size counter (correctly synchronized) but the
/// actual payload the completion touches is left to the caller's
/// Consumer with NO enforced synchronization -- this is the root
/// cause: the public safe API lets two threads race on that payload.
pub struct Queue {
    pub size: Arc<AtomicUsize>,
    pub inner: RawCommandQueue,
}

impl Queue {
    pub fn new() -> Self {
        Queue { size: Arc::new(AtomicUsize::new(0)), inner: RawCommandQueue }
    }

    pub unsafe fn enqueue_unchecked<'a, 'b, 'r: 'b, E: 'b + FnOnce(&'r RawCommandQueue) -> Result<RawEvent>, C: 'a + Consumer + Clone>
        (&'r self, supplier: E, consumer: C) -> Result<Event<C>> {
        let inner = supplier(&self.inner)?;
        let evt = Event::new(inner, consumer);

        if self.size.fetch_add(1, Ordering::AcqRel) == usize::MAX {
            panic!("Queue size overflow");
        }

        let size = self.size.clone();
        if let Err(e) = evt.on_complete_silent(move |_, _| {
            size.fetch_sub(1, Ordering::AcqRel);
        }) {
            self.size.fetch_sub(1, Ordering::AcqRel);
            return Err(e);
        }

        Ok(evt)
    }

    /// Safe wrapper as would exist in blaze-rs (e.g. `enqueue_write_buffer`,
    /// `enqueue_read_buffer`): callers never write `unsafe` even though the
    /// underlying call is `unsafe fn`. This is the "modular unsafe function"
    /// -- the crate hides the unsafety behind a safe-looking entry point.
    pub fn enqueue_op<C: Consumer + Clone>(&self, consumer: C) -> Event<C> {
        unsafe {
            self.enqueue_unchecked(|_q| Ok(RawEvent::new()), consumer).unwrap()
        }
    }
}

