use poc_lib::{Queue, Consumer, AtomicPayload};
use std::sync::Arc;
use std::cell::UnsafeCell;
use std::thread;
use std::time::Duration;

#[derive(Clone)]
struct MyConsumer {
    payload: Arc<AtomicPayload>,
}

impl Consumer for MyConsumer {
    fn buffer(&self) -> Arc<AtomicPayload> {
        self.payload.clone()
    }
}

fn main() {
    // No `unsafe` anywhere in this file.
    let queue = Queue::new();
    let payload = Arc::new(AtomicPayload(UnsafeCell::new(0)));

    let consumer = MyConsumer { payload: payload.clone() };

    // Safe call into the crate; internally calls the unsafe
    // enqueue_unchecked, exactly like blaze-rs's safe enqueue wrappers do.
    let evt = queue.enqueue_op(consumer.clone());

    // Fire the "driver" completion callback asynchronously, just like a
    // real OpenCL/CUDA driver thread would when the GPU op finishes.
    evt.raw.clone().fire_completion_async();

    // Meanwhile, the main thread also mutates the same payload directly,
    // believing enqueue_op synchronizes access via the event -- but the
    // completion path only updates the atomic refcount, not the buffer.
    let p = payload.clone();
    let writer = thread::spawn(move || {
        for i in 0..1000u64 {
            unsafe_write(&p, i); // plain write through UnsafeCell, no atomics
            thread::sleep(Duration::from_micros(100));
        }
    });

    // Concurrently, the "completion" side (simulated inside the library on
    // another thread) also writes to the same UnsafeCell-backed payload
    // through the consumer captured by the completion closure.
    let reader_payload = payload.clone();
    let reader = thread::spawn(move || {
        for _ in 0..1000u64 {
            let v = unsafe_read(&reader_payload);
            std::hint::black_box(v);
            thread::sleep(Duration::from_micros(100));
        }
    });

    writer.join().unwrap();
    reader.join().unwrap();
    println!("done racing");
}

// These helpers only use safe-looking APIs (no `unsafe` keyword at the
// call site in main), mirroring how a safe Consumer::buffer() accessor
// in blaze-rs hands back raw shared memory with no synchronization.
fn unsafe_write(p: &Arc<AtomicPayload>, v: u64) {
    p.0.set(v);
}

fn unsafe_read(p: &Arc<AtomicPayload>) -> u64 {
    p.0.get()
}

