pub(crate) unsafe fn try_enqueue_waiter(
    &self,
    current: BlockedState,
    new: BlockedState,
    success: Ordering,
) -> Result<(), OnceState> {
    let prev =
        match self.0.compare_exchange(current.into(), new.into(), success, Ordering::Relaxed) {
            Ok(prev) => prev,
            Err(prev) => prev,
        };

    match prev {
        prev if prev == current.into() => Ok(()),
        prev => Err(prev.try_into().expect(POISON_PANIC_MSG)),
    }
}

poc_lib_rs:
use std::cell::UnsafeCell;
use std::sync::atomic::{AtomicU8, Ordering};

pub type BlockedState = u8;

const INCOMPLETE: u8 = 0;
const RUNNING: u8 = 1;
const COMPLETE: u8 = 2;

pub struct MiniOnceCell<T> {
    state: AtomicU8,
    value: UnsafeCell<Option<T>>,
}

// Same Sync justification as real OnceCell: access to `value` is supposedly
// gated by `state`, so it is claimed safe to share across threads.
unsafe impl<T: Send> Sync for MiniOnceCell<T> {}

impl<T: Copy> MiniOnceCell<T> {
    pub fn new() -> Self {
        Self { state: AtomicU8::new(INCOMPLETE), value: UnsafeCell::new(None) }
    }

    // Faithful reconstruction of conquer-once's try_enqueue_waiter: note the
    // `Ordering::Relaxed` hard-coded as the *failure* ordering regardless of
    // what the caller requested for success. This is the root-cause bug.
    pub(crate) fn try_enqueue_waiter(
        &self,
        current: BlockedState,
        new: BlockedState,
        success: Ordering,
    ) -> Result<(), u8> {
        match self.state.compare_exchange(current, new, success, Ordering::Relaxed) {
            Ok(prev) => {
                debug_assert_eq!(prev, current);
                Ok(())
            }
            Err(prev) => Err(prev),
        }
    }

    /// Safe public API: the initializing thread.
    pub fn init(&self, val: T) {
        if self.try_enqueue_waiter(INCOMPLETE, RUNNING, Ordering::Acquire).is_ok() {
            unsafe {
                *self.value.get() = Some(val);
            }
            self.state.store(COMPLETE, Ordering::Release);
        }
    }

    /// Safe public API: a "waiter" thread that spins until it sees COMPLETE.
    /// Because `try_enqueue_waiter`'s failure branch reads with `Relaxed`,
    /// observing COMPLETE here does NOT synchronize-with the initializer's
    /// `Release` store, so the read below races with `init`'s write.
    pub fn wait_and_get(&self) -> Option<T> {
        loop {
            match self.try_enqueue_waiter(INCOMPLETE, RUNNING, Ordering::Acquire) {
                Ok(()) => return None, // we became the initializer instead
                Err(prev) if prev == COMPLETE => {
                    return unsafe { *self.value.get() };
                }
                Err(_) => continue, // still RUNNING, spin
            }
        }
    }
}

