use std::cell::Cell;
use std::mem::MaybeUninit;
use std::ptr;
use std::rc::Rc;

/// Allocates an uninitialized byte buffer of `len` bytes and hands it to `run`.
fn uninit_slice<R>(len: usize, run: impl FnOnce(&mut [MaybeUninit<u8>]) -> R) -> R {
    let mut buf: Vec<MaybeUninit<u8>> = Vec::with_capacity(len);
    // SAFETY: MaybeUninit<u8> does not require initialization.
    unsafe { buf.set_len(len) };
    run(&mut buf)
}

/// Writes every chunk yielded by `chunks` contiguously starting at `dst`.
///
/// # Safety
/// Caller must ensure `dst` points to at least `chunks.map(|c| c.len()).sum()` writable bytes.
unsafe fn write_byte_chunks<'a>(mut dst: *mut u8, chunks: impl Iterator<Item = &'a [u8]>) {
    for chunk in chunks {
        let len = chunk.len();
        unsafe {
            ptr::copy_nonoverlapping(chunk.as_ptr(), dst, len);
            dst = dst.add(len);
        }
    }
}

/// # Safety
/// Caller must ensure every byte of `slice` has actually been initialized.
unsafe fn slice_assume_init_ref(slice: &[MaybeUninit<u8>]) -> &[u8] {
    unsafe { &*(slice as *const [MaybeUninit<u8>] as *const [u8]) }
}

/// Target function (reconstructed from spacetimedb-sats).
///
/// # Safety
/// Caller must guarantee that `total_len == chunks.map(|c| c.len()).sum()` for the
/// *actual* sequence `chunks` will yield when iterated exactly once, right here.
pub unsafe fn concat_byte_chunks_buf<'a, R>(
    total_len: usize,
    chunks: impl Iterator<Item = &'a [u8]>,
    run: impl FnOnce(&[u8]) -> R,
) -> R {
    uninit_slice(total_len, |buf: &mut [MaybeUninit<u8>]| {
        let dst = buf.as_mut_ptr().cast();
        debug_assert_eq!(total_len, buf.len());
        // SAFETY (as claimed by the module):
        // 1. `buf.len() == total_len`
        // 2. `buf` cannot overlap with anything yielded by `chunks`.
        unsafe { write_byte_chunks(dst, chunks) }
        // SAFETY (as claimed by the module): every byte of `buf` was initialized
        // above because `total_len == chunks.map(|c| c.len()).sum()`.
        let bytes = unsafe { slice_assume_init_ref(buf) };
        run(bytes)
    })
}

/// A one-shot iterator that, depending on a *shared* flag flipped by ordinary
/// safe code, either yields the full slice once (measuring pass) or yields
/// nothing at all (writing pass) -- no `unsafe` involved anywhere here.
struct ShrinkingChunks {
    data: &'static [u8],
    shrunk: Rc<Cell<bool>>,
    done: bool,
}

impl Iterator for ShrinkingChunks {
    type Item = &'static [u8];
    fn next(&mut self) -> Option<Self::Item> {
        if self.done {
            return None;
        }
        self.done = true;
        if self.shrunk.get() {
            None
        } else {
            Some(self.data)
        }
    }
}

/// Fully SAFE public API (mirrors how spacetimedb-sats wraps the unsafe
/// primitive behind a safe function). It measures `total_len` with one pass
/// over a fresh iterator, then does the real write with *another* fresh
/// iterator that -- because of the shared flag it flipped in between, using
/// only safe `Cell` mutation -- now yields fewer bytes than it did before.
pub fn concat_safe(data: &'static [u8]) -> Vec<u8> {
    let shrunk = Rc::new(Cell::new(false));

    let counting_iter = ShrinkingChunks { data, shrunk: shrunk.clone(), done: false };
    let total_len: usize = counting_iter.map(|c| c.len()).sum();

    // Purely safe mutation: flips the shared flag between the two passes.
    shrunk.set(true);

    let write_iter = ShrinkingChunks { data, shrunk: shrunk.clone(), done: false };

    // The module's own doc/safety comment claims this is fine because
    // `total_len == write_iter.map(|c| c.len()).sum()`, but that invariant
    // was only true for `counting_iter`, not for `write_iter`.
    unsafe { concat_byte_chunks_buf(total_len, write_iter, |bytes| bytes.to_vec()) }
}

