    // Fully safe call: concat_safe() internally measures total_len against one
    // iterator pass and then writes with a second pass that yields nothing,
    // leaving the whole buffer uninitialized while it's exposed as `&[u8]`.
    let v = poc_lib::concat_safe(data);
