/// Safe-looking wrapper: constructs a handle from a raw pointer with no
/// null/validity check, mirroring `BlkidTopology::new` in libblkid-rs.
pub struct SymtHandle(pub *const CSymbolTable);

impl SymtHandle {
    pub fn new(ptr: *const CSymbolTable) -> SymtHandle {
