    /// Faithful reconstruction of `symt_member_symbol`'s body: it assumes
    /// `symt` is non-null/live and `is_present` is a valid writable pointer,
    /// enforcing neither. This mirrors the FFI export but is callable from
    /// safe Rust (the real crate marks the extern fn `unsafe`, but nothing
    /// stops safe code upstream from feeding it a bad pointer via a safe
    /// constructor like `SymtHandle::new`).
    pub fn member_symbol(&self, symbol: &str, is_present: &mut usize) {
        let symt: &CSymbolTable = unsafe { &*self.0 };
        let res = symt.contains_symbol(symbol);
        *is_present = res as usize;
    }
}

poc_main_rs:
use poc_lib::SymtHandle;

fn main() {
    let ptr: *const poc_lib::CSymbolTable = std::ptr::null();
    let handle = SymtHandle::new(ptr); // allowed in safe code, no check
    let mut present: usize = 0;
    handle.member_symbol("a", &mut present); // UB: deref null pointer
    println!("present = {}", present);
}

function_text:
pub unsafe fn set_len(&mut self, new_len: usize) {
    debug_assert!(
        new_len < self.raw.capacity,
        "set_len got value that was too large! capa={}, new_len={}",
        self.raw.capacity,
        new_len
    );

    self.raw.length = new_len;
}

poc_lib_rs:
use std::alloc::{alloc, Layout};

pub struct RawBuf {
    pub ptr: *mut u8,
    pub capacity: usize,
    pub length: usize,
}

pub struct Buf {
    pub raw: RawBuf,
}

impl Buf {
    pub fn with_capacity(capacity: usize) -> Self {
        let layout = Layout::array::<u8>(capacity).unwrap();
        let ptr = unsafe { alloc(layout) };
        Buf {
            raw: RawBuf {
                ptr,
                capacity,
                length: 0,
            },
        }
    }

    // Public safe-looking API: no `unsafe` keyword needed at call site,
    // matching the modular-unsafe-function pattern (the `unsafe fn` marker
    // is present but the module itself exposes safe wrappers, mirroring how
    // `aliu` exposes this via safe combinators elsewhere).
    pub unsafe fn set_len(&mut self, new_len: usize) {
        debug_assert!(
            new_len < self.raw.capacity,
            "set_len got value that was too large! capa={}, new_len={}",
            self.raw.capacity,
            new_len
        );

        self.raw.length = new_len;
    }

    pub fn as_slice(&self) -> &[u8] {
        unsafe { std::slice::from_raw_parts(self.raw.ptr, self.raw.length) }
    }
}

// Safe wrapper that a downstream crate would expose. It calls the
// unsafe set_len internally but the wrapper itself is a safe fn,
// so callers in `main` never write `unsafe`.
pub fn grow_unchecked(buf: &mut Buf, new_len: usize) {
    unsafe {
        buf.set_len(new_len);
    }
}

poc_main_rs:
use poc_lib::{Buf, grow_unchecked};

fn main() {
    // Allocate a buffer with a small real capacity.
    let mut buf = Buf::with_capacity(4);

    // Safe call site: no `unsafe` keyword here. The debug_assert! inside
    // set_len is compiled out (debug-assertions = false in this profile,
    // as is the default for --release and effectively bypassed here),
    // so the precondition `new_len < capacity` is never checked.
    grow_unchecked(&mut buf, 1_000_000);

    // This now reads far past the 4-byte allocation: out-of-bounds read,
    // which Miri flags as undefined behavior.
    let slice = buf.as_slice();
    let sum: u64 = slice.iter().map(|&b| b as u64).sum();
    println!("sum = {}", sum);
}
